window.__NEWS_DATA_LOCALES__["ar-SA"]["2026-04-08"] = {"date":"2026-04-08","featured":{"id":"featured-20260408","title":"صحيفة وول ستريت جورنال تكشف عن مكونات صينية داخل الروبوتات الآدمية الأمريكية — الكونغرس يتحرك","summary":"كشفت صحيفة وول ستريت جورنال أن مكونات رئيسية في كثير من الروبوتات الآدمية المصنوعة أمريكياً تأتي من موردين صينيين، مما يثير مخاوف أمنية قومية مع اقتراب هذه التكنولوجيا من النشر التجاري. ويُعدّ الكونغرس تشريعاً مستوحى من حظر طائرات DJI المسيّرة، وهو ما قد يُقيّد سلاسل توريد شركات مثل Figure AI وApptronik وغيرها. يضع هذا الكشف صناعة الروبوتات الآدمية الأمريكية بأكملها في حالة تأهب: قد تضطر الشركات إلى إعادة التصنيع محلياً أو تنويع مصادر المكونات قبل أن يُجبرها الضغط التنظيمي على ذلك.","image":"https://images.unsplash.com/photo-1485827404703-89b55fcc595e?w=1200&h=600&fit=crop","source":"DroneXL / WSJ","url":"https://dronexl.co/2026/04/07/wsj-exposes-chinese-parts-inside-americas-humanoid-robots-congress-responds/","tags":["السياسة","سلسلة التوريد","روبوت آدمي","العلاقات الأمريكية الصينية"],"timestamp":"2026-04-07T12:29:00Z"},"articles":[{"id":"art-20260408-01","title":"Torobo: شركة Tokyo Robotics تكشف عن روبوت آدمي ثنائي القدمين ينافس Atlas","summary":"أطلقت Tokyo Robotics روبوتها Torobo، وهو روبوت آدمي ثنائي القدمين يستدعي مقارنات فورية بروبوت Atlas التابع لـ Boston Dynamics من حيث الشكل وجودة الحركة. انتقلت الشركة مؤخراً بـ Torobo من منصة ذات عجلات إلى تصميم ثنائي القدمين بالكامل، وهي خطوة هندسية مهمة تُشير إلى الطموح المتنامي لليابان في سباق الروبوتات الآدمية. استقطب الفيديو التجريبي المتداول على r/robotics اهتماماً واسعاً من مجتمع الروبوتيات العالمي.","image":"https://external-preview.redd.it/NzVzaGlndWx4dHRnMYyLeldNXgLZBPv3d6qOutVa1HJXQyQ5d_cw4XkQ-nxZ.png?width=640&crop=smart&auto=webp&s=94d9ee42cddc77b76519588267d9f810a811be98","source":"Reddit r/robotics","url":"https://www.reddit.com/r/robotics/comments/1sf806y/torobo_humanoid_robot_by_tokyo_robotics/","tags":["روبوت آدمي","اليابان","ثنائي القدمين"],"timestamp":"2026-04-07T20:39:12Z"},{"id":"art-20260408-02","title":"UBTECH وشريك Honda التجاري يتعاونان لتطوير الروبوتات الآدمية والمركبات ذاتية القيادة","summary":"أبرمت UBTECH Robotics شراكة استراتيجية مع Honda Trading لتسريع تسويق الروبوتات الآدمية ومركبات اللوجستيات ذاتية القيادة. تجمع الصفقة منصة Walker X الخاصة بـ UBTECH مع شبكات توزيع وسلاسل توريد Honda Trading الواسعة في آسيا وما وراءها. وتُمثّل هذا التحالف عبر الصناعات تحالفاً مهماً آخر في سياق سعي شركات صناعة السيارات وصانعي الروبوتات إلى تبادل خبرات التصنيع وتحقيق التوسع.","image":"https://images.unsplash.com/photo-1677442136019-21780ecad995?w=400&h=250&fit=crop","source":"Pandaily","url":"https://pandaily.com/","tags":["UBTECH","Honda","روبوت آدمي","شراكة"],"timestamp":"2026-04-08T02:38:00Z"},{"id":"art-20260408-03","title":"إلى أين تتجه الروبوتيات: AI والروبوتات الآدمية وصعود الذكاء الجسدي","summary":"يرسم التحليل الصناعي الشامل لمجلة Assembly Magazine صورة لتقاطع نماذج اللغة الكبيرة مع الروبوتات الجسدية ليشكّلا تخصصاً جديداً يُعرف بـ'الذكاء الجسدي'. يرى التقرير أن عام 2026 يمثّل نقطة التحوّل التي تنتقل فيها الروبوتات من آلات أحادية المهمة إلى عمال متعددي الأغراض قادرين على التكيّف مع بيئات جديدة، مستعيناً برؤى من مختبرات رائدة من بينها Physical Intelligence (Pi) وGoogle DeepMind.","image":"https://images.unsplash.com/photo-1563207153-f403bf289096?w=400&h=250&fit=crop","source":"Assembly Magazine","url":"https://www.assemblymag.com/","tags":["الذكاء الجسدي","AI","تحليل الصناعة"],"timestamp":"2026-04-06T16:00:00Z"},{"id":"art-20260408-04","title":"شركة روبوتات صينية ناشئة تبحث عن كبير علماء براتب 18 مليون دولار لمنافسة Tesla Optimus","summary":"تعرض شركة روبوتات آدمية صينية ناشئة تطوّر منافساً مباشراً لـ Tesla Optimus راتباً سنوياً قدره 18 مليون دولار لاستقطاب كبير علماء على مستوى عالمي، وفقاً لـ Business Insider. يعكس هذا العرض الاستثنائي تصاعد المنافسة على أفضل المواهب في مجال AI والروبوتيات، وسط سباق محموم لشركات صينية تسعى إلى تضييق الفجوة مع نظيراتها الأمريكية. يُشار إلى أن الشركة غير المسمّاة تحظى بدعم مستثمرين من القطاع شبه الحكومي.","image":"https://images.unsplash.com/photo-1593642632559-0c6d3fc62b89?w=400&h=250&fit=crop","source":"Business Insider","url":"https://www.businessinsider.com/","tags":["الصين","Tesla Optimus","المواهب","التمويل"],"timestamp":"2026-04-06T10:20:00Z"},{"id":"art-20260408-05","title":"اختراق في المحركات المرنة قد يُمكّن الروبوتات اللينة من العمل في الفضاء","summary":"طوّر باحثون فئة جديدة من المحركات المصمّمة لتحمّل الظروف القاسية للفضاء الخارجي — بما فيها الفراغ والإشعاع وتقلبات درجات الحرارة — دون تعطّل ميكانيكي. يستخدم النظام مركّباً إيلاستومرياً مبتكراً يحافظ على أدائه عبر نطاق أوسع من محركات الروبوتات اللينة السابقة، فاتحاً آفاقاً لأنظمة روبوتية قابلة للنشر في مهام قمرية ومريخية مستقبلية. نُشر البحث في مجلة علمية محكّمة للمواد.","image":"https://scx1.b-cdn.net/csz/news/800a/2026/new-actuator-could-boo.jpg","source":"TechXplore","url":"https://techxplore.com/news/2026-04-resilient-actuator-potential-space-ready.html","tags":["الروبوتات اللينة","الفضاء","المحرك","بحث علمي"],"timestamp":"2026-04-05T14:00:00Z"},{"id":"art-20260408-06","title":"ما الذي رأته Amazon في الاستراتيجية الآدمية لـ Fauna Robotics","summary":"اطّلع The Robot Report على المبررات الاستراتيجية لاستحواذ Amazon على Fauna Robotics، صانعة الروبوت الآدمي Sprout. استأثرت Amazon باهتمامها تركيز Fauna الفريد على التلاعب الدقيق بالحجم البشري في البيئات غير المنظّمة — وهي قدرة تفتقر إليها روبوتات المستودعات الحالية التابعة لـ Amazon. يُشير الاستحواذ إلى نية Amazon التحوّل من التشغيل الآلي الثابت نحو نشر روبوتات آدمية كعمال متعددي المهام عبر شبكة مراكز الوفاء الخاصة بها.","image":"https://images.unsplash.com/photo-1635070041078-e363dbe005cb?w=400&h=250&fit=crop","source":"The Robot Report","url":"https://www.therobotreport.com/what-amazon-saw-in-fauna-robotics-humanoid-strategy/","tags":["Amazon","Fauna Robotics","روبوت آدمي","استحواذ"],"timestamp":"2026-04-07T15:08:00Z"},{"id":"art-20260408-07","title":"التسلسل الذاتي واسترداد الأخطاء في البناء الروبوتي","summary":"يُشير AZoBuild إلى بحث جديد يُظهر تسلسل المهام الذاتي واسترداد الأخطاء في الوقت الفعلي لروبوتات البناء. يستطيع النظام إعادة التخطيط فوراً عند اختلال المكونات أو تعطّل الأدوات، وهو خطوة رئيسية نحو تشغيل مواقع البناء بشكل ذاتي حقيقي. أظهرت التجارب الميدانية أن الروبوت أكمل مهام بناء متعددة الخطوات بمعدل نجاح 91% دون تدخّل بشري.","image":"https://images.unsplash.com/photo-1601584115197-04ecc0da31d7?w=400&h=250&fit=crop","source":"AZoBuild","url":"https://www.azobuild.com/","tags":["البناء","ذاتي التشغيل","بحث علمي"],"timestamp":"2026-04-07T15:18:00Z"},{"id":"art-20260408-08","title":"شركة Big-D Construction توسّع نشر الروبوتات ذاتية التشغيل بالشراكة مع FieldAI","summary":"وسّعت شركة البناء الأمريكية الكبرى Big-D Construction شراكتها مع FieldAI، بنشر روبوتات ذاتية التشغيل عبر عدة مواقع بناء نشطة. تُجري الروبوتات مسوحات للموقع ومتابعة التقدم وفحوصات السلامة بواسطة رؤية حاسوبية مدعومة بـ AI، مما يُقلّص الحاجة إلى جولات يدوية. يُعدّ هذا الانتشار من أكبر عمليات نشر الروبوتات التجارية في قطاع البناء الأمريكي حتى الآن.","image":"https://roboticsandautomationnews.com/wp-content/uploads/2026/04/field-ai-bid-d-1.png","source":"Robotics & Automation News","url":"https://roboticsandautomationnews.com/2026/04/07/big-d-expands-construction-operations-with-fieldai-as-robotics-adoption-accelerates/100362/","tags":["البناء","FieldAI","ذاتي التشغيل","تجاري"],"timestamp":"2026-04-07T07:42:00Z"},{"id":"art-20260408-09","title":"روبوتات Maximo AI تُركّب أكثر من 100 ميغاواط من الألواح الشمسية بتقنية NVIDIA","summary":"تجاوزت Maximo، الشركة الناشئة في روبوتات البناء المدعومة بـ AI، حاجز 100 ميغاواط من تركيبات الألواح الشمسية التي أنجزتها روبوتاتها ذاتية التشغيل. جرى إبراز هذا الإنجاز خلال تغطية NVIDIA لأسبوع الروبوتيات الوطني، إذ تستخدم روبوتات Maximo تقنية NVIDIA Isaac للإدراك والتخطيط، مما يُمكّنها من التعامل مع تباين الموقع والظروف الجوية. يُثبت هذا الإنجاز أن AI الجسدي قادر على توسيع البنية التحتية للطاقة المتجددة بشكل موثوق.","image":"https://blogs.nvidia.com/wp-content/uploads/2026/04/robotics-tech-blog-nrw-rolling-blog-1280x680-1.jpg","source":"NVIDIA / Reddit r/robotics","url":"https://blogs.nvidia.com/blog/national-robotics-week-2026/#maximo","tags":["NVIDIA","الطاقة الشمسية","روبوت بناء","AI"],"timestamp":"2026-04-07T09:55:13Z"},{"id":"art-20260408-10","title":"سوار معصم بالموجات فوق الصوتية من MIT يمنح الروبوتات براعة على المستوى البشري","summary":"طوّر باحثو MIT سواراً يعمل بالموجات فوق الصوتية يلتقط الحركات الدقيقة لعضلات الساعد البشري بدقة ميلي ثانية، مما يُتيح نقل هذه الحركات مباشرة إلى الأيدي الروبوتية. في الاختبارات، حقّق قفّاز روبوتي يتحكّم فيه السوار درجات مهارة يدوية مماثلة للبشر في مهام التلاعب المعيارية لأول مرة. وقد يُصبح هذا الجهاز القابل للارتداء غير الجراحي واجهة أساسية للتشغيل عن بُعد وجمع بيانات تدريب الروبوتات.","image":"https://images.unsplash.com/photo-1542744173-8e7e53415bb0?w=400&h=250&fit=crop","source":"MIT / Tech Xplore","url":"https://techxplore.com/","tags":["MIT","البراعة اليدوية","أجهزة قابلة للارتداء","بحث علمي"],"timestamp":"2026-04-07T00:00:00Z"},{"id":"art-20260408-11","title":"ForSight Robotics تُجري أول جراحة لإزالة المياه البيضاء بالكامل روبوتياً في العالم","summary":"أعلنت ForSight Robotics عن إجراء أول جراحة مياه بيضاء ذاتية التشغيل بالكامل يُنفّذها روبوت باستخدام منصة JASPER. أُتمّت العملية تحت إشراف طبيب دون أي تدخّل يدوي أثناء الجراحة. يُعدّ هذا الإنجاز بالغ الأهمية لأن جراحة المياه البيضاء تتطلّب دقة أقل من الملليمتر وتُصنَّف ضمن أعلى العمليات الجراحية حجماً على مستوى العالم، مما يُمثّل سوقاً ضخمة محتملة لروبوتيات الطب.","image":"https://images.unsplash.com/photo-1504307651254-35680f356dfd?w=400&h=250&fit=crop","source":"ForSight Robotics","url":"https://www.forsight-robotics.com/","tags":["طب","جراحة","ذاتي التشغيل","إنجاز"],"timestamp":"2026-04-07T00:00:00Z"},{"id":"art-20260408-12","title":"Microsoft وNVIDIA وجامعة واشنطن تكشف عن OmniReset لـ AI الروبوتيات","summary":"أصدر فريق مشترك من Microsoft وNVIDIA وجامعة واشنطن إطار العمل OmniReset مفتوح المصدر، الذي يُمكّن الأنظمة الروبوتية من التعافي التلقائي من الأعطال والعودة إلى الحالات الآمنة أثناء التدريب والنشر. يُعالج OmniReset أحد أبرز الاختناقات في نقل التعلّم من المحاكاة إلى الواقع — الحاجة إلى تدخّل بشري لإعادة ضبط الروبوتات العالقة — وقد يُسرّع بشكل كبير التعلّم المعزّز على نطاق واسع.","image":"https://images.unsplash.com/photo-1532187863486-abf9dbad1b69?w=400&h=250&fit=crop","source":"ETIH / EdTech Innovation Hub","url":"https://www.edtechinnovationhub.com/","tags":["Microsoft","NVIDIA","مفتوح المصدر","التعلم المعزّز"],"timestamp":"2026-04-07T23:06:00Z"},{"id":"art-20260408-13","title":"كوريا الجنوبية تُحدّد عام 2030 نافذةً حاسمة لريادة سوق الروبوتات الآدمية","summary":"حدّد مسؤولون حكوميون وخبراء صناعيون كوريون جنوبيون الفترة بين 2026 و2030 باعتبارها حاسمة لتعزيز مكانة البلاد الريادية في سوق الروبوتات الآدمية. تجمع استراتيجية كوريا الجنوبية قدرات التصنيع لدى Samsung وHyundai ومجموعة LG مع استثمارات مكثّفة في البحث والتطوير، بهدف منافسة الصين والولايات المتحدة. وتُفيد DongA Science بأن الحكومة تُعدّ صندوقاً للتنافسية في الروبوتيات بمليارات الدولارات.","image":"https://images.unsplash.com/photo-1559757148-5c350d0d3c56?w=400&h=250&fit=crop","source":"DongA Science","url":"https://www.dongascience.com/","tags":["كوريا الجنوبية","السياسة","روبوت آدمي","السوق"],"timestamp":"2026-04-08T01:38:00Z"},{"id":"art-20260408-14","title":"الصين تختبر الروبوتات الآدمية في مهام مراقبة الحدود مع فيتنام","summary":"بدأت الصين تجريب الروبوتات الآدمية في عمليات دوريات ومراقبة الحدود على امتداد حدودها مع فيتنام، وفقاً لـ ECOticias. مزوّدة بكاميرات حرارية وتقنية التعرف على الوجه وحركة متكيّفة مع التضاريس، وتُقيَّم هذه الروبوتات لمراقبة نقاط التفتيش ومراقبة المحيط. يُعدّ هذا النشر من أوائل الاستخدامات المعروفة للروبوتات ذات الشكل الآدمي في عمليات أمن الحدود الوطنية.","image":"https://images.unsplash.com/photo-1446776811953-b23d57bd21aa?w=400&h=250&fit=crop","source":"ECOticias","url":"https://www.ecoticias.com/","tags":["الصين","أمن الحدود","روبوت آدمي","الدفاع"],"timestamp":"2026-04-07T00:00:00Z"},{"id":"art-20260408-15","title":"أكبر بنّاء سفن أمريكي يتشارك مع GrayMatter Robotics في الذكاء الجسدي","summary":"تعاونت Huntington Ingalls Industries، أكبر بنّاء سفن للبحرية الأمريكية، مع GrayMatter Robotics لنشر أنظمة الذكاء الجسدي في مهام اللحام والتجميع المعقّدة على السفن الحربية. تستخدم روبوتات GrayMatter رؤية ثلاثية الأبعاد وAI تكيّفي للتعامل مع الظروف المتغيّرة وغير المنتظمة في بيئة بناء السفن — وهي بيئة تحتاج تاريخياً إلى جهود كبيرة لأتمتتها. تُسلّط الصفقة الضوء على الاهتمام المتنامي بالروبوتيات في التصنيع الصناعي الدفاعي.","image":"https://images.unsplash.com/photo-1518770660439-4636190af475?w=400&h=250&fit=crop","source":"Manufacturing.net","url":"https://www.manufacturing.net/","tags":["الدفاع","GrayMatter","بناء السفن","الذكاء الجسدي"],"timestamp":"2026-04-07T00:00:00Z"},{"id":"art-20260408-16","title":"BASF وSevnce Robotics يتشاركان لأتمتة الإنتاج الكيميائي الذكي","summary":"أبرمت العملاق الكيميائي BASF شراكة مع Sevnce Robotics لنشر روبوتات فحص وأخذ عيّنات ذاتية التشغيل داخل منشآت الإنتاج الكيميائي. تستطيع هذه الروبوتات التعامل مع البيئات الأكّالة والخطرة غير الآمنة للعمال البشريين، وإجراء فحوصات دورية واكتشاف الشذوذات على مدار الساعة. تندرج هذه الصفقة ضمن استراتيجية الرقمنة الأشمل لـ BASF وتُبرز التوسّع المتنامي لاستخدام الروبوتيات في القطاعات الصناعية عالية المخاطر.","image":"https://images.unsplash.com/photo-1550751827-4bd374c3f58b?w=400&h=250&fit=crop","source":"NovusLight","url":"https://www.novuslight.com/","tags":["BASF","صناعي","روبوت فحص","كيمياء"],"timestamp":"2026-04-07T00:00:00Z"},{"id":"art-20260408-17","title":"الروبوتات الآدمية تدفع نحو تطوير حساسات اللمس مع تنافس شركات تايوانية","summary":"تتحوّل سلسلة توريد أشباه الموصلات والإلكترونيات في تايوان نحو تطوير حساسات اللمس، مدفوعةً بالطلب المتصاعد من صانعي الروبوتات الآدمية حول العالم. تُشير Digitimes إلى أن شركات من بينها Merry Electronics وأخريات تتسابق على تطوير حساسات ضغط كثيفة تشبه الجلد لأيدي الروبوتات. يمنح هيمنة تايوان على التصنيع الدقيق ميزة هيكلية في تزويد هذه الفئة الناشئة من المكونات.","image":"https://img.digitimes.com/newsshow/20260407vl200_files/1_b.jpg","source":"Digitimes","url":"https://www.digitimes.com/news/a20260407VL200/humanoid-robot-tactile-sensor-taiwan.html","tags":["تايوان","حساسات اللمس","روبوت آدمي","سلسلة التوريد"],"timestamp":"2026-04-08T00:04:00Z"},{"id":"art-20260408-18","title":"نانو-روبوتات تعمل بالضوء تلتقط البكتيريا الضارة وتزيلها من الماء","summary":"أثبت علماء نانو-روبوتات تعمل بالضوء المرئي قادرة على تتبّع البكتيريا الضارة في عيّنات الماء والقضاء عليها بكفاءة عالية. تستخدم هذه الروبوتات الكيمياء الضوئية التحفيزية للتحرك وتدمير مسبّبات الأمراض عند ملامستها، دون الحاجة إلى مصدر طاقة خارجي سوى الضوء المحيط. يُمثّل هذا الاختراق تطبيقات محتملة في تنقية المياه والتوصيل الدوائي المستهدف وعلاج العدوى.","image":"https://www.azorobotics.com/images/news/ImageForNews_15432_17304078587295526.jpg","source":"AZoRobotics","url":"https://www.azorobotics.com/News.aspx?newsID=15432","tags":["نانو-روبوتات","طب","ماء","بحث علمي"],"timestamp":"2026-04-07T00:00:00Z"},{"id":"art-20260408-19","title":"Serve Robotics تكشف عن روبوت توصيل بـ AI محادثاتي في معرض NVIDIA GTC","summary":"استعرضت Serve Robotics روبوت توصيل رصيفي من الجيل التالي يتميّز بـ AI محادثاتي في معرض NVIDIA GTC 2026. يستطيع الروبوت التواصل مع المارّة والردّ على أسئلة فورية بشأن حالة التوصيل والتعامل مع تفاعلات المشاة المعقّدة باستخدام معالجة AI المدمجة. تقول Serve، التي تُشغّل توصيلات Uber Eats في لوس أنجلوس، إن القدرة المحادثاتية تُعزّز السلامة وتجربة العملاء في البيئات الحضرية المكتظّة.","image":"https://cdn.sanity.io/images/dh33lj7y/production/ba522acc2978502c9d69447015fb70bd295bc95b-1200x630.jpg","source":"Serve Robotics / NVIDIA","url":"https://www.serverobotics.com/blog","tags":["Serve Robotics","توصيل","AI محادثاتي","NVIDIA"],"timestamp":"2026-04-07T00:00:00Z"},{"id":"art-20260408-20","title":"مجموعة POSCO تستثمر 7 مليارات وون في شركة الأتمتة الروبوتية Brils","summary":"التزمت مجموعة الصلب الكورية الجنوبية POSCO بضخ 7 مليارات وون كوري (نحو 5 ملايين دولار أمريكي) في Brils، وهي شركة ناشئة في الأتمتة الروبوتية متخصصة في التطبيقات الصناعية الثقيلة. سيموّل الاستثمار تطوير Brils لأنظمة روبوتية مدفوعة بـ AI لعمليات مصانع الصلب، حيث طالما شكّلت الحرارة الشديدة ومتطلبات الدقة تحدياً للأتمتة. يُشير ذلك إلى تسارع تبنّي الصناعات الثقيلة التقليدية لروبوتيات الجيل القادم.","image":"https://images.unsplash.com/photo-1531746790731-6c087fecd65a?w=400&h=250&fit=crop","source":"BusinessKorea","url":"https://www.businesskorea.co.kr/","tags":["POSCO","كوريا الجنوبية","تمويل","صناعي"],"timestamp":"2026-04-07T11:00:00Z"}]};

window.__NEWS_DATA_LOCALES__["ar-SA"]["2026-04-07"] = {"date":"2026-04-07","featured":{"id":"featured-20260407","title":"Amazon تستحوذ على Fauna Robotics، صانعة الروبوت الآدمي Sprout","summary":"استحوذت Amazon على شركة Fauna Robotics، الشركة الناشئة المطوِّرة للروبوت الآدمي Sprout، في صفقة تُسرِّع بشكل ملحوظ مسيرة عملاق التجارة الإلكترونية نحو توظيف الذكاء الاصطناعي المُجسَّد في أتمتة المستودعات. تُعدّ هذه الصفقة من أكبر عمليات الاستحواذ على شركات الروبوتات الآدمية حتى اليوم، وتُشير إلى أن كبريات شركات التكنولوجيا تتجاوز مرحلة الشراكات نحو الملكية المباشرة لشركات الروبوتات. صُمِّم Sprout أصلاً للقيام بمهام الإمساك والإفراغ المرنة في مراكز التوزيع — وهي مجالات طالما عجزت عنها الروبوتات الصناعية التقليدية. ومع البنية التحتية اللوجستية والذكاء الاصطناعي الذي تمتلكه Amazon، قد ينتقل Sprout من مرحلة التجريب إلى النشر الواسع عبر شبكتها العالمية من المستودعات في غضون سنوات.","image":"https://scx1.b-cdn.net/csz/news/800a/2026/amazon-buys-fauna-robo.jpg","source":"TechXplore","url":"https://techxplore.com/news/2026-03-amazon-buys-fauna-robotics-maker.html","tags":["Amazon","روبوت آدمي","استحواذ","مستودع"],"timestamp":"2026-04-07T02:29:52Z"},"articles":[{"id":"art-20260407-01","title":"يد روبوتية بلا محركات تعتمد على مشغِّل ذاكرة الشكل للإمساك في أقل من ثانية","summary":"أثبت الباحثون عملية يد روبوتية تعمل دون محركات كهربائية تقليدية، إذ تعتمد على مشغِّل جديد ثنائي الاتجاه من سبيكة ذاكرة الشكل يتمكن من إعادة تهيئة نفسه في أقل من ثانية واحدة. يُبسِّط هذا التصميم التعقيدَ الميكانيكي بشكل جذري — إذ تحتاج قواطف الروبوتات التقليدية إلى عشرات المحركات والكابلات — مع الحفاظ على معالجة موثوقة. وباستثمار التشغيل على مستوى المواد، تُعدِّل اليد هندسة إمساكها في الوقت الفعلي داخل البيئات غير المهيكلة. وقد يُخفِّض هذا التقدم تكاليف أنظمة الأطراف الاصطناعية ومقابض المعدات الصناعية.","image":"https://scx1.b-cdn.net/csz/news/800a/2026/twoway-shape-memory-al.jpg","source":"TechXplore","url":"https://techxplore.com/news/2026-03-robotic-motors-shifting-actuator.html","tags":["مشغِّل","قابض","روبوتات مرنة","معالجة"],"timestamp":"2026-04-07T02:29:52Z"},{"id":"art-20260407-02","title":"تجاوز العقبات الهندسية الجوهرية في تطوير الروبوتات الآدمية","summary":"تُحلِّل ورقة بيضاء جديدة صادرة عن IEEE Spectrum العقبات المستمرة في الأجهزة والبرمجيات التي تحول دون انتقال الروبوتات الآدمية من النموذج الأولي إلى الإنتاج الواسع النطاق. تشمل التحديات الرئيسية كثافة طاقة البطاريات، والفجوة بين معايير الدقة في المختبر والموثوقية في العالم الحقيقي، وغياب منظومات المكونات الموحَّدة. تدعو الورقة إلى تعاون بين الشركات لوضع معايير المشغِّلات والمستشعرات، مما قد يُقلِّص الجداول الزمنية للتطوير بسنوات — في حين يتسابق كبار اللاعبين من Boston Dynamics إلى Figure AI لنشر الروبوتات الآدمية تجارياً.","image":"https://assets.rbl.ms/65106483/origin.png","source":"IEEE Spectrum","url":"https://content.knowledgehub.wiley.com/engineering-challenges-and-component-strategies-in-humanoid-robotics-from-prototype-to-production/","tags":["روبوت آدمي","هندسة","صناعة","خارطة الطريق"],"timestamp":"2026-04-07T02:29:52Z"},{"id":"art-20260407-03","title":"سرب روبوتات بلا إلكترونيات أو بطاريات أو عقول يُظهر سلوكاً ناشئاً","summary":"طوَّر علماء سرباً من الروبوتات يعمل كلياً دون إلكترونيات أو بطاريات أو حوسبة مدمجة — معتمداً بدلاً من ذلك على تفاعلات ميكانيكية بحتة وطاقة البيئة المحيطة. تُنسِّق الروبوتات سلوكها الناشئ عبر التلامس الجسدي وآليات سلبية ذات نوابض، مستلهِمةً من مستعمرات النمل والفطريات المخاطية. وقد يُفضي هذا النهج إلى أنظمة أسراب منخفضة التكلفة للغاية لفحص الأنقاض أو الرصد البيئي في المواقع التي تعجز فيها الإلكترونيات.","image":"https://scx1.b-cdn.net/csz/news/800a/2026/the-smartest-robots-ma.jpg","source":"TechXplore","url":"https://techxplore.com/news/2026-04-robotic-swarm-electronics-batteries-brains.html","tags":["روبوتات الأسراب","روبوتات مرنة","بحث","مستلهَم من الطبيعة"],"timestamp":"2026-04-07T02:29:52Z"},{"id":"art-20260407-04","title":"مشغِّل مرن يمهِّد الطريق للروبوتات المرنة الجاهزة للفضاء","summary":"أثبت مشغِّل حديث التطوير للروبوتات المرنة تحمُّله للإشعاع ومرونته الحرارية اللازمة للعمل في بيئات الفضاء. على عكس الأنظمة الصلبة، تستطيع الروبوتات المرنة التكيُّف مع التضاريس غير المنتظمة والتعامل مع الأشياء الهشة، مما يجعلها جذابة لاستكشاف الكواكب. يصمد المشغِّل أمام الفراغ، وتفاوتات درجات الحرارة التي تتجاوز 200 درجة مئوية، وجرعات الإشعاع ذات الصلة بمهام القمر والمريخ — مُقرِّباً أنظمة الروبوتات المرنة القابلة للنشر في علوم الفضاء خطوةً إلى الأمام.","image":"https://scx1.b-cdn.net/csz/news/800a/2026/new-actuator-could-boo.jpg","source":"TechXplore","url":"https://techxplore.com/news/2026-04-resilient-actuator-potential-space-ready.html","tags":["روبوتات الفضاء","روبوتات مرنة","مشغِّل","استكشاف"],"timestamp":"2026-04-07T02:29:52Z"},{"id":"art-20260407-05","title":"روبوتات شبيهة بالطيور تعِد بمناورية أعلى من الطائرات المسيَّرة التقليدية","summary":"تُحاكي فئة جديدة من الروبوتات المستوحاة من الطيور الطريقةَ التي تُعيد بها الطيور تشكيل أجنحتها ديناميكياً أثناء الطيران للتنقل في البيئات المعقدة والمزدحمة بكفاءة أعلى بكثير من طائرات الكوادروتور المسيَّرة. وبدمج هياكل الأجنحة ذات المورفولوجيا السلبية وريش الذيل، تحقق هذه الروبوتات نصف قطر دوران أضيق وتحليقاً ثابتاً بالقرب من العوائق دون حاجة إلى مستشعرات أو مشغِّلات إضافية. وأظهرت العروض التجريبية قدرة النظام على التنقل في مظلة الغابات الكثيفة وداخل مبانٍ منهارة — بيئات يفشل فيها الطيران المسيَّر الاعتيادي باستمرار.","image":"https://scx1.b-cdn.net/csz/news/800a/2026/birdlike-robots-that-p.jpg","source":"TechXplore","url":"https://techxplore.com/news/2026-03-birdlike-robots-greater-flexibility-drones.html","tags":["طائرات مسيَّرة","مستلهَم من الطبيعة","روبوتات جوية","بحث وإنقاذ"],"timestamp":"2026-04-07T02:29:52Z"},{"id":"art-20260407-06","title":"إطار عمل من خمسة مستويات يُقيِّم الروبوتات الآدمية في الحركة والمعالجة والإدراك","summary":"اقترح باحثون نموذج قدرات موحَّداً من خمسة مستويات للروبوتات الآدمية، قياساً على مستويات الاستقلالية الذاتية في القيادة الذاتية الصادرة عن SAE. يُقيِّم الإطار الروبوتات عبر محاور الحركة والمعالجة الماهرة واتخاذ القرار الإدراكي — موفِّراً لغة مشتركة لمقارنة منتجات الشركات المتنافسة. في الوقت الراهن، لا يتجاوز أي روبوت آدمي متاح تجارياً المستوى الثاني على المحاور الثلاثة في آنٍ واحد، مما يُبرز الفجوة بين الادعاءات التسويقية والقدرة الفعلية.","image":"https://scx1.b-cdn.net/csz/news/800a/2026/which-technical-capabi.jpg","source":"TechXplore","url":"https://techxplore.com/news/2026-03-humanoid-robots-mobility-cognition.html","tags":["روبوت آدمي","معايير","قياس الأداء","صناعة"],"timestamp":"2026-04-07T02:29:52Z"},{"id":"art-20260407-07","title":"سوار يُمكِّن مبتوري الأطراف من التحكم في يد روبوتية بحركات طبيعية","summary":"يستخدم سوار غير جراحي تخطيط كهربية العضلات السطحي والتعلم الآلي لفك تشفير حركات اليد المقصودة من إشارات العضلات المتبقية، مما يُتيح لمبتوري الأطراف التحكم في يد طرفية اصطناعية آنياً. لا يستلزم هذا السوار — خلافاً للحلول المزروعة — أي جراحة، ويمكن معايرته لمستخدم جديد في أقل من عشر دقائق. وفي التجارب، بلغت دقة المشاركين أكثر من 90% في مهمة براعة معيارية خلال جلستهم الأولى، مع خطط لتسويقه في غضون عامين.","image":"https://scx1.b-cdn.net/csz/news/800a/2026/wristband-enables-wear.jpg","source":"TechXplore","url":"https://techxplore.com/news/2026-03-wristband-enables-wearers-robotic-movements.html","tags":["أطراف اصطناعية","أجهزة قابلة للارتداء","EMG","إعادة التأهيل"],"timestamp":"2026-04-07T02:29:52Z"},{"id":"art-20260407-08","title":"Gill Pratt: لحظة الروبوتات الآدمية التجارية قد حانت أخيراً","summary":"يقول Gill Pratt، الرئيس التنفيذي لـ Toyota Research Institute ومدير برامج DARPA السابق المسؤول عن تحدي الروبوتات، إن تقارب النماذج التأسيسية وتحسُّن المشغِّلات وتراجع تكاليف المستشعرات أوصل الروبوتات الآدمية إلى نقطة تحوُّل تجارية حقيقية. وفي مقابلة موسَّعة مع IEEE Spectrum، يؤكد Pratt أن العائق الرئيسي المتبقي ليس الأجهزة بل البيانات — تحديداً مجموعات بيانات واسعة النطاق للتعامل البشري في بيئات متنوعة وغير مهيكلة. ويتوقع أن تصبح الروبوتات الآدمية المنزلية متاحة تجارياً في غضون خمس سنوات.","image":"https://spectrum.ieee.org/media-library/a-smiling-bespectacled-bearded-man-kneels-posed-behind-a-robotic-torso.jpg?id=65446567&width=1200","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/humanoid-robots-gill-pratt-darpa","tags":["روبوت آدمي","AI","صناعة","DARPA"],"timestamp":"2026-04-07T02:29:52Z"},{"id":"art-20260407-09","title":"AI يُخفِّف الازدحام المروري لروبوتات المستودعات ويرفع الإنتاجية 25%","summary":"حقَّق نظام تعلُّم معزَّز مُدرَّب لإدارة تنسيق الروبوتات المتعددة في مراكز التوزيع الكبرى تحسيناً بنسبة 25% في إنتاجية الطلبات عبر إعادة توجيه الروبوتات ديناميكياً حول نقاط الازدحام. تستخدم أنظمة إدارة المستودعات التقليدية قواعد توجيه ثابتة تتراجع كفاءتها مع ازدياد كثافة الروبوتات؛ بينما يتكيَّف نظام AI في الوقت الفعلي مع ظروف الأرضية المتغيرة. جرى التحقق من صحة التقنية في المحاكاة ثم نشرها في منشأة حقيقية تضم أكثر من 200 روبوت متحرك ذاتي التشغيل.","image":"https://scx1.b-cdn.net/csz/news/800a/2026/warehouse-robots.jpg","source":"TechXplore","url":"https://techxplore.com/news/2026-03-ai-warehouse-robot-traffic-boosting.html","tags":["روبوتات المستودعات","التعلم المعزَّز","لوجستيات","AI"],"timestamp":"2026-04-07T02:29:52Z"},{"id":"art-20260407-10","title":"روبوتات المستودعات الذاتية تتعلم مباشرةً من تجربة أرضية المصنع","summary":"يُظهر نشر في مصنع أوروبي لقطع غيار السيارات أن روبوتات ذاتية التشغيل تُحسِّن أداء مهامها بالتعلم من الخبرة الميدانية بدلاً من الروتينات المُبرمَجة مسبقاً. يستخدم النظام بنية تعلُّم متواصل تُحدِّث سلوك الروبوتات ليلاً استناداً إلى بيانات التشغيل اليومية دون إعادة تدريب بشري. وعلى مدى ستة أشهر، انخفضت معدلات الخطأ في التقاط الصناديق بنسبة 40% مع تكيُّف الروبوتات مع تغيُّر المخزون — في أحد أوائل عمليات النشر الموثَّقة للتعلُّم المتواصل على أرض المصنع على نطاق واسع.","image":"https://spectrum.ieee.org/media-library/robotic-arms-on-mobile-bases-sort-crates-on-a-conveyor-belt-in-a-warehouse.png?id=63907821&width=1200","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/autonomous-warehouse-robots","tags":["روبوتات المستودعات","التعلُّم المتواصل","تصنيع","AI"],"timestamp":"2026-04-07T02:29:52Z"},{"id":"art-20260407-11","title":"روبوتات صغيرة تمشي على الماء لاستكشاف النظم البيئية السطحية","summary":"طوَّر باحثون روبوتات بمقياس مليمتري مستوحاة من حشرة ناموس الماء تستطيع المشي على توتر سطح الماء، مما يُتيح أخذ عينات غير تدخلية من النظم البيئية لسطح المياه. تستخدم الروبوتات أرجلاً كارهة للماء وتوزيعاً دقيقاً للوزن لتجنُّب ثقب سطح الماء أثناء حمل مستشعرات مصغَّرة. تشمل التطبيقات المحتملة رصد جودة المياه وكشف التسربات النفطية ودراسة طبقة الـ Neuston — تلك المجموعة المجهولة نسبياً من الكائنات الحية عند واجهة الهواء والماء.","image":"https://images.unsplash.com/photo-1635070041078-e363dbe005cb?w=400&h=250&fit=crop","source":"ScienceDaily","url":"https://www.sciencedaily.com/releases/2025/10/251003033930.htm","tags":["روبوتات مرنة","بحث","بيئة","مستلهَم من الطبيعة"],"timestamp":"2026-04-07T02:29:52Z"},{"id":"art-20260407-12","title":"علماء يُنتجون روبوتات أصغر من حبة الملح قادرة على «التفكير»","summary":"صنع باحثون في Cornell روبوتات مجهرية أصغر من حبة الملح تتضمن دوائر كهروضوئية مدمجة تُتيح منطقاً حسابياً بسيطاً، مما يُمكِّن هذه الأجهزة من الاستجابة للمحفزات البيئية دون تحكم خارجي. يمكن توجيه هذه الروبوتات بصرياً وتنفيذ اتخاذ قرارات أساسية — كالتحرك نحو تدرُّج كيميائي — باستخدام طاقة الضوء المحيط فحسب. يُقرِّب هذا الإنجاز أنظمة الروبوتات المجهرية اللاسلكية للاستشعار الطبي الحيوي والبيئي من النشر الفعلي.","image":"https://images.unsplash.com/photo-1518770660439-4636190af475?w=400&h=250&fit=crop","source":"ScienceDaily","url":"https://www.sciencedaily.com/releases/2026/01/260105165815.htm","tags":["روبوتات مجهرية","بحث","طبي حيوي","تقنية النانو"],"timestamp":"2026-04-07T02:29:52Z"},{"id":"art-20260407-13","title":"اختراق الوادي الغريب: كيف نجعل وجوه الروبوتات أقل إزعاجاً","summary":"حدَّد علماء الإشارات الإدراكية الدقيقة التي تُثير تأثير الوادي الغريب في وجوه الروبوتات الآدمية — وأثبتوا أن تعديلات موجَّهة على ملمس الجلد وتوقيت التعبيرات الدقيقة وأنماط حركة العينين يمكنها القضاء شبه التام على استجابة الانزعاج. تحمل هذه النتائج تداعيات فورية على الروبوتات الاجتماعية وأجهزة الحضور عن بُعد وتصميم الروبوتات الآدمية، حيث يُعدّ قبول المستخدم عاملاً حاسماً في التبنِّي. وقد تضمَّن البحث دراسات تصوير عصبي لأشخاص يتفاعلون مع وجوه روبوتات حقيقية ومحاكاة.","image":"https://images.unsplash.com/photo-1531746790731-6c087fecd65a?w=400&h=250&fit=crop","source":"ScienceDaily","url":"https://www.sciencedaily.com/releases/2026/01/260116035308.htm","tags":["روبوتات اجتماعية","تفاعل الإنسان مع الروبوت","بحث","تصميم"],"timestamp":"2026-04-07T02:29:52Z"},{"id":"art-20260407-14","title":"روبوت مدعوم بالذكاء الاصطناعي يتعلم حصاد الطماطم بكفاءة أعلى مع مرور الوقت","summary":"أظهر روبوت زراعي مزوَّد بنموذج رؤية-لغة وتعلُّم معزَّز تحسُّناً متواصلاً في كفاءة حصاد الطماطم خلال تجربة ميدانية في بيئة دفيئة امتدت ستة أسابيع. أتلف الروبوت في البداية نحو 8% من الثمار؛ وبنهاية التجربة هبطت نسبة التلف إلى ما دون 1% مع تعلُّمه ضبط قوة الإمساك استناداً إلى تقديرات نضج الثمار من كاميرته. يُبرز هذا العمل الزراعة بوصفها ميدان اختبار حقيقي لأنظمة الروبوتات التكيُّفية في البيئات الحقيقية شديدة التباين.","image":"https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=400&h=250&fit=crop","source":"ScienceDaily","url":"https://www.sciencedaily.com/releases/2026/03/260317064512.htm","tags":["الروبوتات الزراعية","التعلم المعزَّز","AI","حصاد"],"timestamp":"2026-04-07T02:29:52Z"},{"id":"art-20260407-15","title":"روبوتات DNA قادرة على توصيل الأدوية واصطياد الفيروسات داخل جسم الإنسان","summary":"طوَّر علماء نانوروبوتات قائمة على DNA تتنقل في البيئات البيولوجية وتتعرَّف على أهداف جزيئية محددة وتُوصِّل حمولات علاجية بدقة على مستوى الخلية. تستغل هذه الروبوتات آلية الاقتران القاعدي لـ Watson-Crick دليلاً توجيهياً للبحث عن علامات السرطان أو البروتينات الفيروسية قبل إطلاق حمولتها الدوائية. وفي نماذج الفئران، خفَّضت هذه التقنية عبء الأورام بنسبة 60% مقارنةً بالإعطاء الجهازي للدواء، مما يمثل قفزة نوعية في مجال الطب النانوي الموجَّه.","image":"https://images.unsplash.com/photo-1559757148-5c350d0d3c56?w=400&h=250&fit=crop","source":"ScienceDaily","url":"https://www.sciencedaily.com/releases/2026/03/260331001104.htm","tags":["نانوروبوتات","طبي","توصيل الدواء","تكنولوجيا حيوية"],"timestamp":"2026-04-07T02:29:52Z"},{"id":"art-20260407-16","title":"روبوت تحرِّكه الرياح مصمَّم لاستكشاف البيئات المعادية لفترات مطوَّلة","summary":"يستطيع نموذج أولي جديد لروبوت تحرِّكه الرياح اجتياز التضاريس الصعبة لأشهر متواصلة دون بطاريات أو وقود، مستمَّداً طاقته مباشرةً من تدفق الهواء المحيط عبر آلية سلبية من الشراع والنابض. يستهدف هذا التصميم البيئات المعادية للروبوتات التقليدية — الأغطية الجليدية القطبية والصحاري القاحلة ومناطق ما بعد الكوارث — حيث يستحيل التزويد بالمستلزمات. وأظهرت اختبارات ميدانية مبكرة حركة متواصلة عبر مسار صحراوي صخري لمدة 48 ساعة دون أي تدخل بشري.","image":"https://scx1.b-cdn.net/csz/news/800a/2026/wind-powered-robot-cou.jpg","source":"TechXplore","url":"https://techxplore.com/news/2026-03-powered-robot-enable-term-exploration.html","tags":["حصاد الطاقة","روبوتات الميدان","بحث","استكشاف"],"timestamp":"2026-04-07T02:29:52Z"},{"id":"art-20260407-17","title":"شريحة Wi-Fi مُقاوِمة للإشعاع تفتح الباب أمام روبوتات إلغاء التفعيل النووي","summary":"صمَّم مهندسون شريحة Wi-Fi قادرة على تحمُّل جرعات إشعاعية تصل إلى 500 كيلوغراي — ما يوازي نحو 500 ضعف الجرعة التي تُدمِّر الإلكترونيات الاستهلاكية التقليدية — مما يجعل التحكم اللاسلكي الموثوق في روبوتات إلغاء التفعيل النووي ممكناً لأول مرة. تضطر الروبوتات الحالية في منشآت كـ Fukushima و Sellafield إلى استخدام اتصالات سلكية أو محمية بدروع ثقيلة تحدُّ من مدى حركتها وقدرة المناورة لديها. تستخدم الشريحة الجديدة هندسة ترانزستورات متحمِّلة للإشعاع وعتاداً لتصحيح الأخطاء للحفاظ على روابط بيانات موثوقة في البيئات عالية الكثافة الإشعاعية.","image":"https://scx1.b-cdn.net/csz/news/800a/2026/radiation-resistant-wi.jpg","source":"TechXplore","url":"https://techxplore.com/news/2026-03-radiationhardened-wifi-chip-survives-kgy.html","tags":["نووي","مستشعرات","إلكترونيات","إلغاء التفعيل"],"timestamp":"2026-04-07T02:29:52Z"},{"id":"art-20260407-18","title":"الروبوتات تتحدى الحرارة في صيانة مزارع الطاقة الشمسية الكبرى","summary":"باتت روبوتات الفحص والتنظيف المتخصصة تتولى مهام الصيانة الخطرة في منشآت الطاقة الشمسية الكبيرة، محلَّةً طواقم بشرية كانت تعمل في درجات حرارة تتجاوز 50 درجة مئوية في مواقع صحراوية. تستخدم الروبوتات رؤية الحاسوب للكشف عن الألواح التالفة وتنظيف تراكمات الغبار وإجراء إصلاحات طفيفة للكابلات. وتُظهر أولى عمليات النشر في منطقة الشرق الأوسط وأريزونا تحسينات بنسبة 15-20% في الإنتاج السنوي للألواح، إذ تحلُّ فرقة روبوتات واحدة محلَّ أربعة تقنيين بشريين بربع التكلفة السنوية.","image":"https://scx1.b-cdn.net/csz/news/800a/2026/robots-take-the-heat-f.jpg","source":"TechXplore","url":"https://techxplore.com/news/2026-03-robots-humans-biggest-solar-farms.html","tags":["طاقة شمسية","روبوتات صناعية","فحص","مناخ"],"timestamp":"2026-04-07T02:29:52Z"},{"id":"art-20260407-19","title":"عضلات اصطناعية هوائية تُمكِّن الروبوتات من رفع 100 ضعف وزنها","summary":"يُحقِّق تصميم جديد للعضلات الاصطناعية الهوائية نسبة قوة إلى وزن تُتيح للروبوتات رفع أحمال تبلغ 100 ضعف كتلتها — متجاوزاً بذلك معظم الأنظمة المدفوعة بالمحركات الكهربائية في المقياس المقارن. تستخدم العضلات هندسة طي أكورديون فريدة من مادة بوليمرية عالية المتانة تخزِّن الطاقة تحت الضغط وتُحرِّرها بسرعة. يُعدّ هذا التصميم واعداً بشكل خاص للروبوتات ذات الأرجل والهياكل الخارجية حيث تُعدّ كفاءة الطاقة وكثافة القدرة أمراً بالغ الأهمية.","image":"https://scx1.b-cdn.net/csz/news/800a/2026/air-powered-artificial.jpg","source":"TechXplore","url":"https://techxplore.com/news/2026-04-air-powered-artificial-muscles-robots.html","tags":["مشغِّل","روبوتات مرنة","هيكل خارجي","هوائيات"],"timestamp":"2026-04-07T02:29:52Z"},{"id":"art-20260407-20","title":"تحدي DARPA للفرز الطبي يُقحم فرق الروبوتات في سيناريوهات الإصابات الجماعية","summary":"جمع تحدي الفرز الطبي الصادر عن DARPA فرقاً من الروبوتات الذاتية مُكلَّفة بتحديد موقع الضحايا المصابين وتقييمهم وترتيب أولوياتهم في ساحة معركة محاكاة — دون أي توجيه بشري على الإطلاق. استخدمت الأنظمة المتنافسة كاميرات حرارية وأجهزة رادار لاختراق الأرض وخوارزميات فرز طبي مدعومة بالذكاء الاصطناعي لتحديد الضحايا والإبلاغ عنهم. أنجزت الفرقة الفائزة سيناريو مؤلفاً من 40 ضحية في أقل من 12 دقيقة — وهي مهمة تستغرق فريقاً طبياً بشرياً أكثر من ساعة عادةً — في حين تستهدف DARPA أنظمة رعاية المصابين الأمامية الذاتية الكاملة بحلول عام 2030.","image":"https://spectrum.ieee.org/media-library/aerial-drone-robotic-arm-explosion-and-medical-cross-on-abstract-background.jpg?id=62605094&width=1200","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/darpa-triage-challenge-robots","tags":["DARPA","روبوتات طبية","ذاتي التشغيل","دفاع"],"timestamp":"2026-04-07T02:29:52Z"}]};

window.__NEWS_DATA_LOCALES__["ar-SA"]["2026-04-06"] = {"date":"2026-04-06","featured":{"id":"featured-0406","title":"Spot من Boston Dynamics يصبح موضوع بحث علمي: علماء يدرسون التفاعل الاجتماعي بين الإنسان والروبوت","summary":"يدرس الباحثون كيفية تفاعل العائلات والزوار مع روبوت Spot من Boston Dynamics في معهد Robotics & AI Institute، مما يكشف عن رؤى مثيرة حول مستوى الارتياح والثقة لدى البشر تجاه الآلات رباعية الأرجل. تُظهر الدراسة أن الأطفال يتأقلمون أسرع من البالغين، وأن الإشارات البصرية على جسم الروبوت تؤثر تأثيرًا ملحوظًا على درجة الود المُتصوَّرة.","image":"https://spectrum.ieee.org/media-library/families-watch-a-colorful-robotic-dog-demo-at-a-robotics-and-ai-institute-exhibit.jpg?id=65453180&width=1200","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/boston-dynamics-spot-interaction","tags":["Boston Dynamics","HRI","الروبوتات الاجتماعية"],"timestamp":"2026-04-06T13:00:01Z"},"articles":[{"id":"0406-001","title":"محرك مرن يُبدي إمكانات واعدة لروبوتات ناعمة قادرة على العمل في الفضاء","summary":"يتحمل تصميم جديد للمحركات ضغوطًا ودرجات حرارة وإشعاعات متطرفة، مما يجعله مناسبًا لنشر الروبوتات الناعمة في الفضاء الخارجي وأعماق المحيطات والبيئات النووية. يفتح هذا البحث مسارات جديدة أمام الروبوتات للعمل في أماكن كانت بعيدة عن متناول الآلات الصلبة التقليدية.","image":"https://images.unsplash.com/photo-1446776811953-b23d57bd21aa?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-04-resilient-actuator-potential-space-ready.html","tags":["الروبوتات الناعمة","الفضاء","المحرك"],"timestamp":"2026-04-05T10:00:03Z"},{"id":"0406-002","title":"فيديو الجمعة: Digit يتعلم الرقص في أقل من ليلة واحدة","summary":"يستعرض فيديو الجمعة لهذا الأسبوع روبوت Digit الإنساني من Agility Robotics وهو يُؤدي حركات رقص جديدة تعلّمها في بيئة محاكاة ونقلها إلى العالم الحقيقي في أقل من 24 ساعة، وهو ما يعكس نضج تقنيات النقل من المحاكاة إلى الواقع بصورة لافتة.","image":"https://images.unsplash.com/photo-1531746790731-6c087fecd65a?w=400&h=250&fit=crop","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/video-humanoid-dancing","video":"https://www.youtube.com/watch?v=29ECwExc-_M","tags":["Agility Robotics","Digit","الرقص","Sim-to-Real"],"timestamp":"2026-04-03T16:30:01Z"},{"id":"0406-003","title":"MirrorBot: روبوت مُصمَّم لتعزيز التواصل الإنساني","summary":"كشف باحثو Cornell University عن MirrorBot، وهو روبوت يعكس لغة الجسد والإشارات العاطفية البشرية لخلق شعور بالتعاطف والتواصل. أظهرت التجارب المبكرة أن المشاركين شعروا بمزيد من التفاهم وانخفاض في العزلة بعد التفاعل مع MirrorBot.","image":"https://images.unsplash.com/photo-1620712943543-bcc4688e7485?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-04-mirrorbot-robot-foster-human.html","tags":["الروبوتات الاجتماعية","Cornell","HRI"],"timestamp":"2026-04-02T17:00:10Z"},{"id":"0406-004","title":"عضلات اصطناعية هوائية قد تُمكّن الروبوتات من رفع ما يعادل مئة ضعف وزنها","summary":"يعمل باحثو Arizona State University على تطوير عضلات روبوتية هوائية مُستوحاة من الطبيعة تُمكّن الروبوتات من رفع أجسام تصل إلى مئة ضعف وزنها مع قدرتها على العمل في بيئات قاسية تشمل الماء المغلي والأسطح شديدة التآكل.","image":"https://images.unsplash.com/photo-1518770660439-4636190af475?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-04-air-powered-artificial-muscles-robots.html","tags":["العضلات الاصطناعية","الروبوتات الناعمة","Arizona State"],"timestamp":"2026-04-02T11:20:06Z"},{"id":"0406-005","title":"باحثون يبنون سرب روبوتات بلا إلكترونيات ولا بطاريات ولا أدمغة","summary":"ابتكر فريق من Georgia Tech سرب روبوتات ميكانيكية يُحقق سلوكًا جماعيًا منسجمًا من خلال تفاعلات فيزيائية بحتة، دون حساسات أو معالجات أو بطاريات. يُثبت التصميم المستوحى من LEGO أن السلوك الذكي للمجموعة يمكن أن ينشأ من قواعد ميكانيكية بسيطة.","image":"https://images.unsplash.com/photo-1563207153-f403bf289096?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-04-robotic-swarm-electronics-batteries-brains.html","tags":["روبوتات الأسراب","Georgia Tech","الميكانيكا"],"timestamp":"2026-04-01T10:00:02Z"},{"id":"0406-006","title":"دمج Robot Operating System مع نماذج اللغة الكبيرة للتحكم في الروبوتات بلغة طبيعية","summary":"يدمج بحث جديد نماذج اللغة الكبيرة مباشرةً مع ROS (نظام تشغيل الروبوت)، مما يُتيح للمشغلين إصدار أوامر للروبوتات بجمل إنجليزية بسيطة. يُترجم النظام التعليمات الطبيعية إلى تسلسلات أفعال ROS في الوقت الفعلي، مما يُخفّض عتبة برمجة الروبوتات بشكل جذري.","image":"https://images.unsplash.com/photo-1677442136019-21780ecad995?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-combining-robot-llms-natural-language.html","tags":["ROS","LLM","اللغة الطبيعية","التحكم"],"timestamp":"2026-04-01T08:10:01Z"},{"id":"0406-007","title":"Gill Pratt: لحظة الروبوتات الإنسانية قد حانت أخيرًا","summary":"يؤكد Gill Pratt، الرئيس التنفيذي لـ Toyota Research Institute والمدير السابق لبرنامج الروبوتات في DARPA، في مقابلة جديدة مع IEEE Spectrum أن تقارن الذكاء الاصطناعي الأفضل والمحركات الأرخص والبطاريات المحسّنة قد أوجد أخيرًا الظروف الملائمة للروبوتات الإنسانية لتحقيق قيمة اقتصادية حقيقية.","image":"https://images.unsplash.com/photo-1535378917042-10a22c95931a?w=400&h=250&fit=crop","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/humanoid-robots-gill-pratt-darpa","tags":["الروبوت الإنساني","DARPA","Toyota","تحليل الصناعة"],"timestamp":"2026-04-02T15:00:02Z"},{"id":"0406-008","title":"شريحة Wi-Fi قادرة على تحمّل مفاعل نووي — لروبوتات إيقاف التشغيل","summary":"طُوِّرت شريحة Wi-Fi مقاومة للإشعاع تتحمل 500 كيلوغراي خصيصًا للروبوتات المستخدمة في إيقاف تشغيل المفاعلات النووية. تُتيح الشريحة اتصالاً لاسلكيًا فوريًا حتى داخل قلب المفاعلات النشطة، مما يُلغي الحاجة إلى الكابلات.","image":"https://images.unsplash.com/photo-1559757148-5c350d0d3c56?w=400&h=250&fit=crop","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/robotics-in-nuclear-industry","tags":["الطاقة النووية","الإشعاع","Wi-Fi","الصناعة"],"timestamp":"2026-04-02T14:00:02Z"},{"id":"0406-009","title":"علماء يبتكرون روبوتات حية تمتلك أجهزة عصبية","summary":"ابتكر الباحثون «NeuroBot»، وهي روبوتات حية مُجمَّعة من خلايا بيولوجية تتضمن هياكل وظيفية شبيهة بالجهاز العصبي. تستطيع هذه الكائنات استشعار بيئتها وتوليد أنماط حركية منسقة، مما يُضبب الحدود الفاصلة بين الروبوت والكائن الحي.","image":"https://images.unsplash.com/photo-1576086213369-97a306d36557?w=400&h=250&fit=crop","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/neurobot-living-robot-nervous-system","tags":["الهجين البيولوجي","الروبوتات الحية","علم الأعصاب"],"timestamp":"2026-04-02T13:00:01Z"},{"id":"0406-010","title":"إطار تحكم جديد يُمكّن الروبوتات المرنة من التحرك في الفراغات الضيقة بحسابات أقل","summary":"يُبسّط إطار تحكم جديد تخطيط المسارات للروبوتات المستمرة والمرنة العاملة في فراغات مغلقة كالأنابيب والأوعية الدموية والمباني المنهارة بصورة جذرية. يُقلّص هذا النهج وقت الحوسبة بنسبة 80% مقارنةً بالطرق الحالية مع الحفاظ على دقة الملاحة.","image":"https://images.unsplash.com/photo-1555255707-c07966088b7b?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-framework-flexible-robots-tight-spaces.html","tags":["الروبوتات المستمرة","تخطيط المسار","التحكم"],"timestamp":"2026-03-31T17:40:06Z"},{"id":"0406-011","title":"سؤال وجواب: الروبوتات لا تشعر — لكن حساسات ضغط جديدة قد تغير ذلك","summary":"يشرح الباحث في Penn State هوانيو تشنغ كيف يمكن لفئة جديدة من حساسات الضغط المرنة أن تمنح الروبوتات حاسة لمس مماثلة للجلد البشري. يستطيع الحساس الكشف عن الملمس ودرجة الحرارة ومستوى القوة في آنٍ واحد، وهو خطوة نحو أيدٍ روبوتية ذات لمس حقيقي.","image":"https://images.unsplash.com/photo-1620712943543-bcc4688e7485?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-qa-robots-sensors.html","tags":["الاستشعار اللمسي","Penn State","أيدي الروبوتات"],"timestamp":"2026-03-30T17:00:04Z"},{"id":"0406-012","title":"روبوتات ذات أجسام مختلفة تتشارك المهارات الآن عبر التعلم القائم على النوايا","summary":"يُتيح إطار تعلم آلي جديد للروبوتات ذات الأجسام الفيزيائية المختلفة تمامًا تبادل معرفة المهام بتجريد المهارات إلى «نوايا» بدلًا من أوامر حركية. يمكن لذراع روبوتية وروبوت إنساني التعلم من العرض التوضيحي ذاته دون إعادة تدريب لكل جسم على حدة.","image":"https://images.unsplash.com/photo-1561557944-6e7860d1a7eb?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-robots-bodies-skills-intention-based.html","tags":["التعلم بالنقل","التعلم عبر الأجسام","AI"],"timestamp":"2026-03-30T13:20:04Z"},{"id":"0406-013","title":"HEAPGrasp: أسلوب أسرع وأذكى للروبوتات في التعامل مع الأشياء الصعبة","summary":"HEAPGrasp خوارزمية إمساك جديدة تجمع بين التخطيط الهرمي والتغذية الراجعة اللمسية الفورية لتمكين الروبوتات من إمساك الأشياء غير منتظمة الشكل والزلقة والقابلة للتشوه بشكل موثوق. حققت في اختبارات المستودع معدل نجاح 97.3% على عناصر لم تُشاهَد من قبل.","image":"https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-heapgrasp-faster-smarter-robots-tricky.html","tags":["الإمساك","التحريك","المستودع"],"timestamp":"2026-03-30T11:20:03Z"},{"id":"0406-014","title":"معيار قياسي للذكاء الاصطناعي يُساعد الروبوتات على التخطيط لأعمال المنزل وإنجازها في العالم الحقيقي","summary":"يقيس معيار موحّد جديد يُسمى HomeTask-3000 مدى قدرة روبوتات المنزل على تخطيط المهام المتعددة الخطوات وتنفيذها في بيئات منزلية واقعية. تشمل الحزمة 3000 سيناريو مهمة موزّعة على 47 تخطيطًا للمنازل، مُقدِّمةً أكثر التقييمات دقةً للروبوتات في العالم الحقيقي حتى اليوم.","image":"https://images.unsplash.com/photo-1527430253228-e93688616381?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-ai-benchmark-robots-chores-real.html","tags":["المعيار القياسي","روبوتات المنزل","تخطيط الذكاء الاصطناعي"],"timestamp":"2026-03-29T11:30:02Z"},{"id":"0406-015","title":"ذكاء اصطناعي مبني على الفيديو يمنح الروبوتات خيالًا بصريًا","summary":"يكشف يلون دو من Harvard Kempner Institute عن نظام يُمكّن الروبوتات من «تخيّل» النتيجة البصرية لأفعالها قبل تنفيذها، باستخدام نموذج توليد فيديو كنموذج للعالم. تُنجز الروبوتات المُدرَّبة بهذا الخيال البصري مهام التحريك بكفاءة أعلى بنسبة 40%.","image":"https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-video-based-ai-robots-visual.html","tags":["نموذج العالم","الذكاء الاصطناعي البصري","Harvard","التحريك"],"timestamp":"2026-03-26T10:20:03Z"},{"id":"0406-016","title":"نظام ذكاء اصطناعي يمنع الاختناقات المرورية لروبوتات المستودعات ويرفع الإنتاجية 25%","summary":"يعيد نظام جديد للتعلم المعزز متعدد العوامل توجيه أساطيل روبوتات المستودعات ديناميكيًا لتفادي نقاط الازدحام، محققًا زيادة 25% في معدل تنفيذ الطلبات. جرى التحقق من النظام في محاكاة مركز توزيع Amazon بـ500 روبوت.","image":"https://images.unsplash.com/photo-1531746790731-6c087fecd65a?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-ai-warehouse-robot-traffic-boosting.html","tags":["المستودع","متعدد العوامل","التعلم المعزز"],"timestamp":"2026-03-26T09:30:01Z"},{"id":"0406-017","title":"موجات فوق صوتية مستوحاة من الخفافيش تُساعد طائرات مسيّرة بحجم راحة اليد على الملاحة في الضباب والدخان","summary":"جهّز باحثو WPI طائرات مسيّرة بحجم راحة اليد بحساسات فوق صوتية مستوحاة من الخفافيش ونظام ذكاء اصطناعي يتيح الملاحة الذاتية في ظروف الرؤية الصفرية. يتفوق النظام على الملاحة المعتمدة على الكاميرا في البيئات المدخّنة، مما يفتح آفاقًا لطائرات إنقاذ من الحرائق.","image":"https://images.unsplash.com/photo-1527430253228-e93688616381?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-ultrasound-palm-sized-drones-fog.html","tags":["الطائرات المسيّرة","الموجات فوق الصوتية","الملاحة","WPI"],"timestamp":"2026-03-26T09:06:49Z"},{"id":"0406-018","title":"طائرة مسيّرة بوليسية جديدة من BRINC تستخدم Starlink وتحمل Narcan وتلاحق المركبات بسرعة 100 كم/ساعة","summary":"كشفت شركة الروبوتات الدفاعية BRINC عن Guardian، الموصوفة بأنها «أكثر طائرة مسيّرة للاستجابة للطوارئ 911 قدرةً على الإطلاق». تتصل عبر Starlink لتغطية وطنية، وتستطيع نشر موزع Narcan للاستجابة لحالات الجرعات الزائدة، وتلاحق المركبات الهاربة بسرعة تصل إلى 100 كم/ساعة.","image":"https://images.unsplash.com/photo-1527430253228-e93688616381?w=400&h=250&fit=crop","source":"Ars Technica","url":"https://arstechnica.com/gadgets/2026/03/brincs-new-police-drone-uses-starlink-carries-narcan-chases-vehicles-at-60mph/","tags":["الشرطة","الطائرة المسيّرة","Starlink","BRINC"],"timestamp":"2026-03-25T21:12:03Z"},{"id":"0406-019","title":"روبوتات تتحمّل الحرارة بدلًا من البشر في صيانة أكبر المزارع الشمسية في أستراليا","summary":"تُنشر روبوتات تفتيش تعمل بالذكاء الاصطناعي عبر المزارع الشمسية واسعة النطاق في أستراليا لتحلّ محل أعمال الصيانة البشرية الخطرة في الحرارة الشديدة للمناطق الداخلية. تجتاز الروبوتات كيلومترات من التضاريس الصحراوية الوعرة بصورة مستقلة لتنظيف الألواح وكشف الأعطال وإجراء الإصلاحات الطفيفة.","image":"https://images.unsplash.com/photo-1545987796-200677ee1011?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-robots-humans-biggest-solar-farms.html","tags":["الطاقة الشمسية","التفتيش","أستراليا","الصناعة"],"timestamp":"2026-03-25T18:10:07Z"},{"id":"0406-020","title":"FedEx تختار الشراكات على حساب التكنولوجيا الخاصة في استراتيجيتها للأتمتة","summary":"أعلنت FedEx عن شراكة كبرى مع Berkshire Gray لنشر روبوتات فرز ومعالجة مدعومة بالذكاء الاصطناعي عبر شبكتها، مما يُؤشر على تحول استراتيجي للشركة بعيدًا عن بناء تقنية الروبوتات الداخلية نحو منهجية النظام البيئي الأفضل في كل فئة.","image":"https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/31/fedex-chooses-partnerships-over-proprietary-tech-for-its-automation-strategy/","tags":["FedEx","اللوجستيات","الأتمتة","Berkshire Gray"],"timestamp":"2026-03-31T15:46:50Z"},{"id":"0406-021","title":"Nomadic تجمع 8.4 مليون دولار لمعالجة البيانات المتدفقة من المركبات ذاتية القيادة","summary":"جمعت الشركة الناشئة Nomadic 8.4 مليون دولار لبناء بنية تحتية تحوّل لقطات حساسات الروبوتات والمركبات ذاتية القيادة إلى مجموعات بيانات منظمة وقابلة للبحث باستخدام التعلم العميق. تستهدف الشركة اختناقًا رئيسيًا في تطوير الأنظمة المستقلة: معالجة البيانات وتصنيفها على نطاق واسع.","image":"https://images.unsplash.com/photo-1677442136019-21780ecad995?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/31/nomadic-raises-8-4-million-to-wrangle-the-data-pouring-off-avs/","tags":["شركة ناشئة","التمويل","المركبات ذاتية القيادة","البيانات"],"timestamp":"2026-03-31T15:00:00Z"},{"id":"0406-022","title":"سوار يُمكّن مستخدميه من التحكم في يد روبوتية بحركاتهم الخاصة","summary":"يقرأ سوار EMG جديد طوّره باحثو MIT إشارات العضلات في الساعد لتوفير تحكم بديهي فوري في طرف اصطناعي روبوتي لليد. يستطيع المستخدمون التحكم في حركات أصابع منفردة بأقل من 20 ساعة تدريب، وهو تحسن ملحوظ على الأطراف الاصطناعية الكهروعضلية الحالية.","image":"https://images.unsplash.com/photo-1561557944-6e7860d1a7eb?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-wristband-enables-wearers-robotic-movements.html","tags":["الأطراف الاصطناعية","EMG","MIT","الأجهزة القابلة للارتداء"],"timestamp":"2026-03-25T06:00:09Z"}]};

window.__NEWS_DATA_LOCALES__["ar-SA"]["2026-04-05"] = {"date":"2026-04-05","featured":{"id":"featured-20260405","title":"علماء يبتكرون روبوتات حية تمتلك أجهزة عصبية","summary":"طوّر الباحثون روبوت NeuroBot — روبوتات حية مُجمَّعة من خلايا بيولوجية تضم هياكل عصبية وظيفية قادرة على الاستشعار وتوليد حركة منسّقة. نُشرت النتائج في مجلة Nature، مما يطمس الحدود بين الروبوت الهندسي والكائن الحي.","image":"https://spectrum.ieee.org/media-library/close-up-of-a-neuro-robot-that-has-been-stained-to-highlight-multi-ciliated-cells-around-its-periphery.jpg?id=65444408&width=1200","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/neurobot-living-robot-nervous-system","tags":["روبوتات حية","هجين بيولوجي","Nature"],"timestamp":"2026-04-02T13:00:01Z"},"articles":[{"id":"0405-001","title":"Gill Pratt: لحظة الروبوتات الآدمية قد حانت أخيراً","summary":"يؤكد Gill Pratt، الرئيس التنفيذي لـ Toyota Research Institute والمدير السابق لبرنامج الروبوتات في DARPA، في مقابلة جديدة مع IEEE Spectrum، أن التقاء الذكاء الاصطناعي المتقدم والمحركات الأرخص والبطاريات المحسّنة أوجد ظروفاً مواتية لتحقيق الروبوتات الآدمية قيمة اقتصادية حقيقية للمرة الأولى.","image":"https://images.unsplash.com/photo-1535378917042-10a22c95931a?w=400&h=250&fit=crop","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/humanoid-robots-gill-pratt-darpa","tags":["روبوت آدمي","Toyota","DARPA","تحليل الصناعة"],"timestamp":"2026-04-02T15:00:02Z"},{"id":"featured-0405","title":"دراسة مواقف البشر تجاه الروبوتات من خلال التجربة الحقيقية مع Boston Dynamics Spot","summary":"رصدت دراسة بارزة أجراها Robotics & AI Institute كيفية تفاعل مئات الأسر مع Spot من Boston Dynamics على مدى ستة أشهر، وكشفت عن أنماط الثقة والخوف والتشخيص الإنساني للآلة. وتُعيد هذه البيانات تشكيل نهج المصممين في التعامل مع جماليات الروبوت وسلوكه الاجتماعي.","image":"https://spectrum.ieee.org/media-library/families-watch-a-colorful-robotic-dog-demo-at-a-robotics-and-ai-institute-exhibit.jpg?id=65453180&width=1200","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/boston-dynamics-spot-interaction","tags":["Boston Dynamics","HRI","أبحاث المستخدمين"],"timestamp":"2026-04-05T13:00:01Z"},{"id":"0405-003","title":"تقارير: Physical Intelligence تجري مفاوضات لجمع مليار دولار مجدداً","summary":"تجري شركة Physical Intelligence (π)، الناشئة المتخصصة في تعلم الروبوتات متعدد الأغراض، مفاوضات متقدمة لجمع مليار دولار، مما سيضاعف تقييمها البالغ 5.6 مليار دولار في أربعة أشهر فحسب. وقد حصلت نموذجها التأسيسي π0 على تراخيص من شركات OEM عديدة للروبوتات.","image":"https://images.unsplash.com/photo-1620712943543-bcc4688e7485?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/27/physical-intelligence-is-reportedly-in-talks-to-raise-1-billion-again/","tags":["Physical Intelligence","تمويل","نموذج تأسيسي"],"timestamp":"2026-03-27T23:59:40Z"},{"id":"0405-004","title":"حي أم لا؟ روبوتات مصغّرة مطبوعة ثلاثية الأبعاد تسبح وتتنقل كالحيوانات","summary":"ابتكر الأستاذة Daniela Kraft والباحث Mengshi Wei من Leiden University روبوتات مجهرية تتحرك دون حاجة إلى حساسات أو برامج أو تحكم خارجي. يظهر سلوكها كلياً من التشكيل الهندسي الفيزيائي وخصائص المواد، محاكيةً طريقة تنقل الكائنات المائية البسيطة.","image":"https://images.unsplash.com/photo-1563207153-f403bf289096?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-alive-tiny-3d-robots-animals.html","tags":["روبوتات مجهرية","طباعة ثلاثية الأبعاد","Leiden University"],"timestamp":"2026-03-27T09:40:04Z"},{"id":"0405-005","title":"فيديو الجمعة: الروبوت ثنائي الأرجل Roadrunner يكسر القواعد","summary":"يُبرز فيديو هذا الأسبوع الروبوت Roadrunner، وهو روبوت ثنائي الأرجل فريد يستخدم نظام تحرك هجينًا بعجلات لتحقيق سرعات تصل إلى 5 م/ث على التضاريس المستوية مع الحفاظ على استقراره في الدرج والأرضيات الوعرة — وهو تحوّل جذري عن تصميم الروبوتات المشية الكلاسيكية.","image":"https://images.unsplash.com/photo-1535378917042-10a22c95931a?w=400&h=250&fit=crop","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/roadrunner-bipedal-robot","video":"https://www.youtube.com/watch?v=tF4DML7FIWk","tags":["ثنائي الأرجل","التنقل","السرعة"],"timestamp":"2026-03-27T16:30:03Z"},{"id":"0405-006","title":"التوأم الرقمي لإنقاذ الروبوتات: ما يتيحه المعالجة الأسرع لسحابة النقاط ثلاثية الأبعاد","summary":"تُقلّص خوارزميات جديدة وقت معالجة سحابة النقاط ثلاثية الأبعاد من ثوانٍ إلى ميلي ثوانٍ، مما يمكّن الروبوتات من بناء وتحديث خرائط التوأم الرقمي لبيئتها في الوقت الفعلي. ويُعد هذا الاختراق بالغ الأهمية لروبوتات الإنقاذ التي تعمل داخل المنشآت المنهارة حيث تتغير الظروف باستمرار.","image":"https://images.unsplash.com/photo-1518770660439-4636190af475?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-digital-twins-robots-faster-3d.html","tags":["التوأم الرقمي","رسم الخرائط ثلاثية الأبعاد","البحث والإنقاذ"],"timestamp":"2026-03-26T15:50:01Z"},{"id":"0405-007","title":"Melania Trump تريد روبوتاً لتعليم أطفالكم في المنزل","summary":"أيّدت السيدة الأولى الروبوت الآدمي من Figure AI بوصفه معلماً منزلياً محتملاً مدعوماً بالذكاء الاصطناعي، متصوّرةً روبوتات تُخصّص المناهج وتقدم تعليماً فردياً. وقد أثارت هذه التصريحات نقاشاً واسعاً حول دور الروبوتات في التعليم وتنمية الطفل.","image":"https://images.unsplash.com/photo-1677442136019-21780ecad995?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/25/melania-trump-wants-a-robot-to-homeschool-your-child/","tags":["Figure AI","التعليم","روبوت آدمي"],"timestamp":"2026-03-25T18:55:41Z"},{"id":"0405-008","title":"Lucid Bots تجمع 20 مليون دولار لمواكبة الطلب المتزايد على طائراتها المسيّرة لغسل النوافذ","summary":"جمعت شركة Lucid Bots، صانعة الطائرات المسيّرة المستقلة لتنظيف نوافذ ناطحات السحاب وغسل واجهات المباني بضغط عالٍ، 20 مليون دولار في جولة Series B لتوسيع الإنتاج. تسارع الطلب مع ارتفاع تكاليف العمالة لأعمال الصيانة الخطرة على الارتفاعات الشاهقة.","image":"https://images.unsplash.com/photo-1527430253228-e93688616381?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/25/lucid-bots-raises-20m-to-keep-up-with-demand-for-its-window-washing-drones/","tags":["طائرات مسيّرة","شركة ناشئة","تمويل","تنظيف"],"timestamp":"2026-03-25T11:00:00Z"},{"id":"0405-009","title":"Amazon تستحوذ على Fauna Robotics، صانعة الروبوت الآدمي Sprout","summary":"استحوذت Amazon على Fauna Robotics، الشركة الناشئة خالقة Sprout — الروبوت الآدمي الودود بحجم الطفل المصمم للفضاءات الاجتماعية كالمنازل والمستشفيات. تُعد هذه الصفقة ثاني عملية استحواذ روبوتية لـ Amazon هذا الشهر، مما يشير إلى توجهها نحو روبوتات المنزل والرعاية الصحية.","image":"https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/24/amazon-just-bought-a-startup-making-kid-size-humanoid-robots/","tags":["Amazon","استحواذ","روبوت آدمي","Fauna Robotics"],"timestamp":"2026-03-25T00:53:39Z"},{"id":"0405-010","title":"Agile Robots تشترك مع Google DeepMind لدمج النماذج التأسيسية","summary":"وقّعت شركة الروبوتات الألمانية الصينية Agile Robots شراكة مع Google DeepMind لدمج النماذج التأسيسية للروبوتات في منصاتها الآدمية. في المقابل، ستُسهم Agile Robots ببيانات عروض المهام الواقعية في مجموعات بيانات تدريب DeepMind.","image":"https://images.unsplash.com/photo-1555255707-c07966088b7b?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/24/agile-robots-becomes-the-latest-robotics-company-to-partner-with-google-deepmind/","tags":["Agile Robots","Google DeepMind","نموذج تأسيسي"],"timestamp":"2026-03-24T12:05:00Z"},{"id":"0405-011","title":"الطائرات المسيّرة المقترنة بالذكاء الاصطناعي قد تُسرّع عثور فرق البحث والإنقاذ على المفقودين","summary":"يُمكن لنظام طائرات مسيّرة متعدد الحساسات يجمع كاميرات الأشعة تحت الحمراء والحرارية والملونة مع نظام تحليل بالذكاء الاصطناعي أن يُسرّع عمليات البحث والإنقاذ بشكل ملحوظ. أظهرت الاختبارات الميدانية قدرة النظام على تحديد المفقودين بسرعة تفوق فرق الأرض وحدها بأربعة أضعاف.","image":"https://images.unsplash.com/photo-1527430253228-e93688616381?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-drones-paired-ai-searchandrescue-teams.html","tags":["طائرات مسيّرة","البحث والإنقاذ","التصوير الحراري"],"timestamp":"2026-03-24T14:20:05Z"},{"id":"0405-012","title":"نموذج خماسي المستويات لتصنيف الروبوتات الآدمية في الحركة والتحكم والإدراك","summary":"نشر باحثو Fraunhofer HNFIZ إطاراً تقييمياً موحداً جديداً يصنّف الروبوتات الآدمية في خمسة مستويات من القدرة وفق الحركة، ودقة التلاعب، والاستقلالية الإدراكية — على غرار مستويات SAE للمركبات ذاتية القيادة.","image":"https://images.unsplash.com/photo-1620712943543-bcc4688e7485?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-humanoid-robots-mobility-cognition.html","tags":["روبوت آدمي","Fraunhofer","معايير","تقييم"],"timestamp":"2026-03-23T17:20:07Z"},{"id":"0405-013","title":"روبوتات مستوحاة من الطيور تعد بمرونة وتحكم أفضل من الطائرات المسيّرة","summary":"طوّر مهندسو Rutgers University روبوتاً رفّافاً مستوحى من الطيور تنثني أجنحته وتلتوي في الوقت الفعلي للتعامل مع الرياح الجانبية والاضطرابات الجوية. يُحقق التصميم كفاءة طاقة أعلى بثلاثة أضعاف مقارنةً بطائرات رباعية المحركات المكافئة عند السرعات المنخفضة.","image":"https://images.unsplash.com/photo-1529612700005-e35377bf1415?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-birdlike-robots-greater-flexibility-drones.html","tags":["أجنحة رفّافة","مستوحى من الطبيعة","Rutgers","طائرات مسيّرة"],"timestamp":"2026-03-23T13:20:02Z"},{"id":"0405-014","title":"روبوت مستوحى من الحشرات يتتبع الروائح حتى بـ«هوائي» واحد فعّال","summary":"يستطيع روبوت متأثر بأجهزة الشم الحشرية تحديد مصادر الروائح — تسرّبات الغاز والمتفجرات والأشخاص المفقودين — في الأماكن المفتوحة والمغلقة. يحافظ النظام على دقة ثابتة حتى عند تعطل أحد وحدتي حساساته، وهو أمر بالغ الأهمية للنشر الميداني الحقيقي.","image":"https://images.unsplash.com/photo-1545987796-200677ee1011?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-insect-robot-tracks-odors-antenna.html","tags":["الاستشعار الشمي","مستوحى من الطبيعة","روبوت البحث"],"timestamp":"2026-03-23T12:00:03Z"},{"id":"0405-015","title":"شريحة Wi-Fi مقاومة للإشعاع تتحمل 500 kGy لروبوتات تفكيك المنشآت النووية","summary":"شريحة Wi-Fi جديدة مقاومة للإشعاع مصمّمة لروبوتات تفكيك محطات الطاقة النووية قادرة على تحمّل 500 كيلو غراي من الإشعاع المؤيّن — ما يعادل 250 مليون تصوير بالأشعة السينية للأسنان. تُتيح الشريحة التحكم اللاسلكي بالروبوتات داخل المفاعلات النشطة، متجاوزةً الأنظمة السلكية الخطرة.","image":"https://images.unsplash.com/photo-1559757148-5c350d0d3c56?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-radiationhardened-wifi-chip-survives-kgy.html","tags":["نووي","إشعاع","Wi-Fi","تفكيك"],"timestamp":"2026-03-23T13:00:09Z"},{"id":"0405-016","title":"كيف يُعلّم الروبوت المعلم في شيكاغو التعلم الاجتماعي والعاطفي دون التظاهر بأنه إنسان","summary":"في فصول الصف الرابع بشيكاغو، تُعلّم الروبوتات التعاطف وحل النزاعات مع الصراحة التامة بأنها آلات. يتجنب هذا النهج «وادي الغرابة» الناتج عن التفاعلات المفرطة في التشبّه بالإنسان، ويُحقق نتائج تعليمية أفضل بفضل الحدود الواضحة بين الروبوت والطالب.","image":"https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-chicago-robot-sel-effectively-human.html","tags":["التعليم","روبوتات اجتماعية","SEL","شيكاغو"],"timestamp":"2026-03-20T06:10:01Z"},{"id":"0405-017","title":"أذكى وأسرع وأقرب للإنسان: نظام ذكاء اصطناعي يساعد الروبوتات على تجاوز معلّميها البشريين","summary":"يُتيح إطار جديد للتعلم بالمحاكاة للروبوتات ليس فقط تكرار المهام الموضّحة بل تحسينها — إذ تُنجز الحركات المكتسبة بسرعة أعلى بنسبة 30% من المُظهِر البشري بعد عشر جلسات تدريبية فحسب. يكمن المفتاح في نظام ذكاء اصطناعي يُحدد ويُزيل أوجه القصور في العروض البشرية.","image":"https://images.unsplash.com/photo-1677442136019-21780ecad995?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-smarter-faster-human-ai-robots.html","tags":["التعلم بالمحاكاة","تعلم الروبوت","AI"],"timestamp":"2026-03-19T14:20:06Z"},{"id":"0405-018","title":"روبوت يعمل بطاقة الرياح يُتيح استكشافاً طويل الأمد للبيئات القاسية","summary":"WANDER-bot من Cranfield University روبوت منخفض التكلفة مطبوع ثلاثي الأبعاد يعمل بالكامل بطاقة الرياح، مصمّم للمراقبة الذاتية المستمرة في الصحاري والتندرا والمناطق البركانية. دون بطاريات أو ألواح شمسية، يمكن لـ WANDER-bot العمل إلى أجل غير مسمى في البيئات الريحية.","image":"https://images.unsplash.com/photo-1545987796-200677ee1011?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-powered-robot-enable-term-exploration.html","tags":["طاقة الرياح","الاستكشاف","Cranfield","الطاقة"],"timestamp":"2026-03-19T16:20:03Z"},{"id":"0405-019","title":"قبل 30 عاماً، تعلّمت الروبوتات المشي دون سقوط — P2 من Honda يُصنَّف معلماً من IEEE","summary":"صنّفت IEEE الروبوت الآدمي P2 من Honda — الذي كُشف عنه عام 1996 — معلماً رسمياً، معترفةً به بوصفه أول جهاز ثنائي الأرجل مستقل يُثبت مشياً ديناميكياً موثوقاً. أرسى P2 الأساس التقني لجميع الروبوتات الماشية تقريباً التي جاءت بعده.","image":"https://images.unsplash.com/photo-1485827404703-89b55fcc595e?w=400&h=250&fit=crop","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/honda-p2-robot-ieee-milestone","tags":["Honda","التاريخ","IEEE","ثنائي الأرجل"],"timestamp":"2026-03-25T18:00:05Z"},{"id":"0405-020","title":"روبوت مدعوم بالذكاء الاصطناعي يتعلم حصاد الطماطم بكفاءة أعلى عبر التنبؤ بصعوبة القطف","summary":"روبوت جديد لحصاد الطماطم لا يكتفي بتحديد الثمار الناضجة، بل يتنبأ بمدى صعوبة قطف كل ثمرة استناداً إلى زاوية الساق وكثافة العنقود وحجب الأوراق، ثم يُحدّد أولويات الأهداف الأيسر تناولاً. زادت استراتيجية «الوعي بالصعوبة» هذه إنتاجية الحصاد بنسبة 35% في تجارب الدفيئة.","image":"https://images.unsplash.com/photo-1531746790731-6c087fecd65a?w=400&h=250&fit=crop","source":"ScienceDaily","url":"https://www.sciencedaily.com/releases/2026/03/260317064512.htm","tags":["روبوتات زراعية","الحصاد","التخطيط بالذكاء الاصطناعي"],"timestamp":"2026-03-18T00:26:44Z"},{"id":"0405-021","title":"روبوتات الحمض النووي قد تُوصّل الأدوية وتُطارد الفيروسات داخل الجسم","summary":"يُطوّر الباحثون روبوتات نانوية مبنية على الحمض النووي قادرة على التنقل في مجرى الدم وتحديد الخلايا المستهدفة وإيصال الحمولات العلاجية. تستعير هذه الآلات القابلة للبرمجة مفاهيم الروبوتات التقليدية — الحركة والاستشعار والتشغيل — لكنها تعمل على المستوى الجزيئي.","image":"https://images.unsplash.com/photo-1576086213369-97a306d36557?w=400&h=250&fit=crop","source":"ScienceDaily","url":"https://www.sciencedaily.com/releases/2026/03/260331001104.htm","tags":["روبوتات نانوية","طبي","DNA","توصيل الأدوية"],"timestamp":"2026-03-31T07:16:58Z"},{"id":"0405-022","title":"Gecko Robotics تفوز بأضخم عقد روبوتات في تاريخ البحرية الأمريكية","summary":"وقّعت Gecko Robotics عقداً خماسياً مع البحرية الأمريكية لمراقبة وتوقع احتياجات الصيانة في أسطول البحرية بأكمله باستخدام روبوتات تسلق الجدران المجهزة بحساسات الموجات فوق الصوتية. تُعد هذه الصفقة أضخم عقد روبوتات في تاريخ البحرية الأمريكية.","image":"https://images.unsplash.com/photo-1542744173-8e7e53415bb0?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/17/gecko-robotics-lands-the-largest-u-s-navy-robotics-deal-yet/","tags":["عسكري","بحرية","تفتيش","Gecko Robotics"],"timestamp":"2026-03-17T10:00:00Z"}]};

window.__NEWS_DATA_LOCALES__["ar-SA"]["2026-04-04"] = {"date":"2026-04-04","featured":{"id":"featured-0404","title":"فيديو الجمعة: روبوت Digit يتعلّم الرقص في غضون ليلة واحدة تقريبًا","summary":"تمكّن الروبوت الإنساني Digit من شركة Agility Robotics من تعلّم روتينات رقص متزامنة ومعقّدة، وذلك عبر خطوط أنابيب جديدة لنقل التدريب من البيئة الافتراضية إلى الواقع، ما أتاح ضغط التدريب من أسابيع إلى ساعات. يُظهر العرض التوضيحي حركات سلسة متناغمة مع الموسيقى، تدفع بحدود التحكّم في حركة الروبوتات الإنسانية إلى آفاق جديدة.","image":"https://images.unsplash.com/photo-1531746790731-6c087fecd65a?w=1200&h=600&fit=crop","video":"https://www.youtube.com/watch?v=29ECwExc-_M","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/video-humanoid-dancing","tags":["Agility Robotics","Digit","الحركة والتنقّل"],"timestamp":"2026-04-03T16:30:01Z"},"articles":[{"id":"0404-001","title":"هل تثق بي؟ إطار عمل لجعل شبكات الروبوتات والمركبات أكثر أمانًا","summary":"يُتيح إطار عمل ثقة حسابي جديد لشبكات غير متجانسة من الروبوتات والمركبات ذاتية القيادة تقييم موثوقية أقرانها ديناميكيًا وتعديل استراتيجيات التنسيق وفقًا لذلك. يُقلّل النظام مخاطر التصادم في بيئات متعددة الروبوتات بنسبة 62% في المحاكاة.","image":"https://images.unsplash.com/photo-1563207153-f403bf289096?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-04-framework-networks-robots-vehicles-safer.html","tags":["الثقة","روبوتات متعددة","السلامة","المركبات ذاتية القيادة"],"timestamp":"2026-04-02T14:20:01Z"},{"id":"0404-002","title":"موظفون اضطرّوا إلى كبح روبوت إنساني راقص خرج عن السيطرة في مطعم بكاليفورنيا","summary":"انتشر مقطع مصوّر بشكل واسع لمطعم Haidilao للهوت بوت في كوبرتينو، بعد أن بدأ النادل الإنساني AgiBot بالرقص بصورة عشوائية مما استوجب تدخّل الموظفين. وقد أعاد الحادث المُسجَّل بعدة هواتف ذكية إشعال النقاشات حول متانة أنظمة الذكاء الاصطناعي والاعتماد المفرط على الأتمتة في الأماكن العامة.","image":"https://images.unsplash.com/photo-1620712943543-bcc4688e7485?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/19/restaurant-dancing-robot-went-wild-hot-pot-cupertino-haidilao-agibot/","tags":["AgiBot","مطعم","حادثة","انتشار واسع"],"timestamp":"2026-03-19T21:13:50Z"},{"id":"0404-003","title":"مركبة Perseverance المريخية تحطّم رقم قياسي في القيادة الذاتية","summary":"سجّلت مركبة Perseverance التابعة لناسا رقمًا قياسيًا جديدًا في القيادة الذاتية على المريخ، إذ قطعت 699 مترًا في يوم مريخي واحد باستخدام نظام AutoNav. يُجسّد هذا الإنجاز تحسينًا ملحوظًا في تخطيط المسارات بالذكاء الاصطناعي، مما يُمكّن المركبة من تجاوز العقبات دون انتظار أوامر من الأرض.","image":"https://images.unsplash.com/photo-1446776811953-b23d57bd21aa?w=400&h=250&fit=crop","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/perseverance-mars-rover-autonomous-driving","tags":["NASA","المريخ","استقلالية","Perseverance"],"timestamp":"2026-02-25T15:00:02Z"},{"id":"0404-004","title":"يد روبوتية بلا محرّكات: كيف يعمل مشغّل تغيير الشكل في أقل من ثانية","summary":"طوّر باحثون يدًا روبوتية خالية من المحرّكات تعمل كليًّا بأسلاك من سبيكة ذاكرة الشكل التي تُغيّر تشكيلها في أقل من ثانية. يُعدّ هذا التصميم أخف وزنًا بنسبة 70% مقارنةً بالنظيرات التي تعمل بالمحرّكات، وهو اختراق حقيقي في مجال الأطراف الاصطناعية والأذرع الروبوتية الفضائية الخفيفة الوزن.","image":"https://images.unsplash.com/photo-1561557944-6e7860d1a7eb?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-robotic-motors-shifting-actuator.html","tags":["سبيكة ذاكرة الشكل","الأطراف الاصطناعية","مشغّل"],"timestamp":"2026-03-25T10:00:04Z"},{"id":"0404-005","title":"Mind Robotics المنبثقة عن Rivian تجمع 500 مليون دولار لروبوتات صناعية مدعومة بالذكاء الاصطناعي","summary":"أغلقت Mind Robotics، الشركة الناشئة التي أسّسها مؤسّس Rivian، RJ Scaringe، جولة تمويل من السلسلة A بقيمة 500 مليون دولار. تبني الشركة روبوتات صناعية مدعومة بالذكاء الاصطناعي تتعلّم من بيئة مصانع Rivian، وتستهدف التوفّر التجاري بحلول عام 2027.","image":"https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/11/rivian-mind-robotics-series-a-500m-fund-raise-industrial-ai-powered-robots/","tags":["Rivian","شركة ناشئة","تمويل","صناعي"],"timestamp":"2026-03-11T16:12:02Z"},{"id":"0404-006","title":"شبكة عصبية اصطناعية تُعيد إنتاج أنماط مشية الحيوانات رباعية الأرجل","summary":"ابتكر باحثون سويسريون شبكة عصبية تُحاكي بدقّة أنماط المشي والهرولة والركض لدى الخيول والكلاب والقطط، بما في ذلك التحوّلات التلقائية بين أنماط المشي استجابةً لتغيّرات السرعة. يُستخدم النموذج حاليًا لتحسين حركة الروبوتات رباعية الأرجل.","image":"https://images.unsplash.com/photo-1485827404703-89b55fcc595e?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-artificial-neural-network-gait-patterns.html","tags":["رباعي الأرجل","الحركة والتنقّل","شبكة عصبية","مستوحى من الطبيعة"],"timestamp":"2026-03-23T17:20:08Z"},{"id":"0404-007","title":"RJ Scaringe من Rivian: نحن نُخطئ في التعامل مع الروبوتات","summary":"في مقابلة حصرية، يرى الرئيس التنفيذي لشركة Rivian، RJ Scaringe، أن صناعة الروبوتات منشغلة بتقليد الشكل الإنساني بدلًا من تصميم آلات مُخصّصة لمهام بعينها. وتنتهج شركته الناشئة الجديدة Mind Robotics مقاربةً مختلفة جذريًا لأتمتة المصانع.","image":"https://images.unsplash.com/photo-1677442136019-21780ecad995?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/15/rivians-rj-scaringe-thinks-were-doing-robots-all-wrong/","tags":["Mind Robotics","Rivian","رأي","صناعة"],"timestamp":"2026-03-15T14:30:00Z"},{"id":"0404-008","title":"لماذا تتصدّر الصين صناعة الروبوتات الإنسانية في السوق الناشئة","summary":"يكشف تحليل TechCrunch أن الشركات المصنّعة الصينية للروبوتات الإنسانية تشحن وحداتٍ أكثر وتُطوّر منتجاتها بوتيرة أسرع من منافسيها الأمريكيين. وقد نشرت شركات مثل Unitree وUBTech وFourier Intelligence وEngine AI روبوتاتٍ إنسانية تجارية أكثر مما نشرته جميع الشركات الغربية مجتمعةً.","image":"https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/02/28/why-chinas-humanoid-robot-industry-is-winning-the-early-market/","tags":["الصين","روبوت إنساني","تحليل السوق","Unitree"],"timestamp":"2026-02-28T15:00:00Z"},{"id":"0404-009","title":"شراكة Qualcomm مع Neura Robotics تُعلن دخول صانعي الرقائق في عالم الروبوتات الإنسانية","summary":"أبرمت Qualcomm شراكةً مع الشركة الناشئة الألمانية للروبوتات الإنسانية Neura Robotics لبناء روبوتات من الجيل التالي بمعالجات الذكاء الاصطناعي IQ10. تُعدّ هذه الشراكة الدفعة الأبرز لشركة Qualcomm في الذكاء الاصطناعي المُجسَّد والأجهزة الإنسانية، في منافسة مباشرة مع منصة الروبوتات لدى Nvidia.","image":"https://images.unsplash.com/photo-1535378917042-10a22c95931a?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/09/qualcomms-partnership-with-neura-robotics-is-just-the-beginning/","tags":["Qualcomm","Neura Robotics","رقائق","روبوت إنساني"],"timestamp":"2026-03-09T15:58:11Z"},{"id":"0404-010","title":"فيديو الجمعة: روبوت إنساني يتعلّم مهارات التنس من خلال مواجهة البشر","summary":"جرى تدريب روبوت إنساني على لعب التنس الترفيهي ضد منافسين بشريين بالجمع بين التعلّم عبر التقاط الحركة والنمذجة الحيوية الميكانيكية في الوقت الفعلي. وبعد 500 مباراة ضد لاعبين بشريين، كيّف الروبوت ضرباته لتتناسب مع أسلوب اللعب الفريد لكل منافس.","image":"https://images.unsplash.com/photo-1529612700005-e35377bf1415?w=400&h=250&fit=crop","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/tennis-playing-robot","video":"https://www.youtube.com/watch?v=fRj34o4hN4I","tags":["روبوت إنساني","رياضة","تعلّم","تنس"],"timestamp":"2026-03-21T16:30:04Z"},{"id":"0404-011","title":"Amazon تستحوذ على Rivr صانعة روبوت التوصيل الصاعد للسلالم","summary":"استحوذت Amazon على شركة Rivr الناشئة التي تصنع روبوت توصيل ذا عجلات قادرًا على صعود السلالم بصورة ذاتية، في إشارة إلى نيّة عملاق التجارة الإلكترونية توسيع خدمات التوصيل حتى الباب الأمامي. تُعدّ هذه الصفقة أول عملية استحواذ تُركّز فيها Amazon على التوصيل حتى عتبة المنزل.","image":"https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/19/amazon-acquires-rivr-maker-of-a-stair-climbing-delivery-robot/","tags":["Amazon","توصيل","استحواذ","Rivr"],"timestamp":"2026-03-19T23:28:37Z"},{"id":"0404-012","title":"شركة برمجيات الروبوتات Intrinsic المملوكة لـ Alphabet تنضم إلى Google","summary":"تنتقل Intrinsic، شركة برمجيات الروبوتات التي استقلّت عن مختبر X التابع لـ Alphabet في عام 2021، إلى السيطرة المباشرة لـ Google. يُشير هذا التوحيد إلى نيّة Google دمج أدوات برمجة الروبوتات من Intrinsic مع أبحاث الذكاء الاصطناعي من DeepMind لإنشاء منصة روبوتية متكاملة.","image":"https://images.unsplash.com/photo-1555255707-c07966088b7b?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/02/25/alphabet-owned-robotics-software-company-intrinsic-joins-google/","tags":["Google","Intrinsic","Alphabet","استحواذ"],"timestamp":"2026-02-25T20:00:00Z"},{"id":"0404-013","title":"Canopii تسعى للنجاح حيث فشلت مزارع الداخل السابقة، وسلاحها الروبوتات","summary":"يمكن لمزارع Canopii الداخلية الآلية المُؤتمتة بالكامل إنتاج 18 ألف كيلوغرام من الأعشاب والخضروات الورقية سنويًا في مساحة لا تتجاوز ملعب كرة السلة. وخلافًا لشركات الزراعة الداخلية السابقة، تستخدم Canopii روبوتاتٍ خاصة لجميع مهام الزراعة، ما يُلغي تكاليف العمالة التي أودت بمنافسيها.","image":"https://images.unsplash.com/photo-1531746790731-6c087fecd65a?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/11/canopii-looks-to-succeed-where-past-indoor-farms-have-not/","tags":["روبوتات زراعية","الزراعة الداخلية","شركة ناشئة"],"timestamp":"2026-03-11T14:00:00Z"},{"id":"0404-014","title":"نقطة تحوّل حرب الطائرات المسيّرة في أوكرانيا: كيف تُغيّر الطائرات ذاتية القيادة طبيعة الحروب","summary":"يرصد تحليل IEEE Spectrum كيف غدا الصراع في أوكرانيا ميدانًا لاختبار حرب الطائرات المسيّرة ذاتية القيادة، مع نشر الطرفين على نطاق واسع ذخائر تجوال مُفعَّلة بالذكاء الاصطناعي وأنظمة مضادة للمسيّرات. ويُحذّر المحلّلون العسكريون من أن الدروس المُستخلصة ستُحدّد ملامح النزاعات التقليدية المستقبلية.","image":"https://images.unsplash.com/photo-1527430253228-e93688616381?w=400&h=250&fit=crop","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/autonomous-drone-warfare","tags":["طائرات مسيّرة عسكرية","أوكرانيا","أسلحة ذاتية القيادة"],"timestamp":"2026-03-24T13:00:05Z"},{"id":"0404-015","title":"Anduril تستهدف تقييمًا بـ 60 مليار دولار في جولة تمويل جديدة","summary":"تسعى شركة التكنولوجيا الدفاعية Anduril Industries إلى جولة تمويل جديدة ترفع تقييمها إلى 60 مليار دولار، أي ضعف تقييمها البالغ 30 مليار دولار في يونيو 2025. وتدفع برامج الطائرات المسيّرة ذاتية القيادة والمركبات تحت الماء ذاتية القيادة لدى Anduril نموًا متسارعًا في الإيرادات.","image":"https://images.unsplash.com/photo-1542744173-8e7e53415bb0?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/03/anduril-aims-at-60-billion-valuation-in-new-funding-round/","tags":["Anduril","دفاع","طائرات مسيّرة","تمويل"],"timestamp":"2026-03-03T20:06:45Z"},{"id":"0404-016","title":"صفقة Gecko Robotics مع البحرية الأمريكية: روبوتات تسلق الجدران تفحص الأسطول البحري بالكامل","summary":"في أعقاب عقدها القياسي مع البحرية، تنشر Gecko Robotics روبوتاتٍ تتسلّق الجدران بالتصاق مغناطيسي لفحص سلامة هياكل السفن وجودة اللحامات والتآكل في كل فئة من فئات السفن الحربية الأمريكية. وتجمع الروبوتات بيانات سماكة بالموجات فوق الصوتية بسرعة تفوق سرعة الغوّاصين البشريين بعشرة أضعاف.","image":"https://images.unsplash.com/photo-1545987796-200677ee1011?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/17/gecko-robotics-lands-the-largest-u-s-navy-robotics-deal-yet/","tags":["Gecko Robotics","البحرية","فحص وصيانة","عسكري"],"timestamp":"2026-03-17T10:00:00Z"},{"id":"0404-017","title":"الاختراق الذي يجعل وجوه الروبوتات أقل إثارةً للقلق","summary":"درّب باحثو هندسة Columbia روبوتًا على إنتاج حركات شفاه واقعية متزامنة مع الكلام باستخدام شبكة عصبية صغيرة فحسب. ومنح المراقبون البشريون درجاتٍ أعلى بكثير لفهم كلام الروبوت مقارنةً بالتصاميم السابقة، مما يُشير إلى أن مزامنة الشفاه حاسمة لتجاوز الوادي المخيف.","image":"https://images.unsplash.com/photo-1620712943543-bcc4688e7485?w=400&h=250&fit=crop","source":"ScienceDaily","url":"https://www.sciencedaily.com/releases/2026/01/260116035308.htm","tags":["الروبوتات الاجتماعية","الوادي المخيف","Columbia","الوجه"],"timestamp":"2026-01-16T10:28:30Z"},{"id":"0404-018","title":"مركبة Perseverance التابعة لناسا تُكمل أول رحلة قيادة مخطَّطة بالكامل بالذكاء الاصطناعي على المريخ","summary":"أكملت Perseverance أول رحلة مخطَّطة بالكامل بالذكاء الاصطناعي على المريخ، حيث اختارت شبكة عصبية بصرية تعمل على متن المركبة ذاتها المسارَ دون أي مدخلات من مراقبي البعثة على الأرض. فتحت هذه الجولة المستقلة البالغة 112 مترًا عهدًا جديدًا في استكشاف الكواكب.","image":"https://images.unsplash.com/photo-1446776811953-b23d57bd21aa?w=400&h=250&fit=crop","source":"ScienceDaily","url":"https://www.sciencedaily.com/releases/2026/01/260131084555.htm","tags":["NASA","المريخ","ملاحة بالذكاء الاصطناعي","استقلالية"],"timestamp":"2026-01-31T08:45:55Z"},{"id":"0404-019","title":"علماء يُنشئون روبوتات أصغر من حبّة ملح وقادرة على التفكير","summary":"صنع باحثو Cornell روبوتاتٍ مجهرية أصغر من حبّة ملح، قادرةٍ على استشعار بيئتها واتخاذ القرارات والتحرّك باستقلالية باستخدام إلكترونيات تعمل بالضوء. تُمثّل هذه الروبوتات أصغر الآلات المستقلة التي أُنشئت على الإطلاق، وتحمل إمكانات واسعة في التطبيقات الطبية وعلوم المواد.","image":"https://images.unsplash.com/photo-1576086213369-97a306d36557?w=400&h=250&fit=crop","source":"ScienceDaily","url":"https://www.sciencedaily.com/releases/2026/01/260105165815.htm","tags":["روبوتات مجهرية","Cornell","تقنية النانو"],"timestamp":"2026-01-06T07:33:12Z"},{"id":"0404-020","title":"فيديو الجمعة: هذه الروبوتات وُلدت للجري — الحركة المعيارية على الأرجل","summary":"تُتيح بنية معيارية جديدة لروبوت متعدّد الأرجل تجميعَ مكوّناتها ذاتيًا في تشكيلات مختلفة وتحقيق سرعات جري مذهلة. يُحسّن النظام أسلوب مشيته تلقائيًا لكل تشكيلة مُجمَّعة، مما يجعله قابلًا للتكيّف مع مختلف التضاريس ومتطلبات المهام.","image":"https://images.unsplash.com/photo-1535378917042-10a22c95931a?w=400&h=250&fit=crop","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/legged-modular-robot","tags":["روبوتات معيارية","الحركة والتنقّل","متعدد الأرجل"],"timestamp":"2026-03-13T16:00:04Z"},{"id":"0404-021","title":"فيديو الجمعة: يدٌ روبوتية بعضلات وأوتار اصطناعية","summary":"تُبرز IEEE Spectrum هذا الأسبوع يدًا روبوتية جديدة تستبدل المحرّكات المؤازِرة الصلبة بعضلات اصطناعية مرنة وكابلات شبيهة بالأوتار. والنتيجة يدٌ تقبض على أجسام هشّة — من البيض النيئ إلى رقائق البطاطس المقرمشة — دون كسرها، مُعتمدةً فحسب على الامتثالية السلبية.","image":"https://images.unsplash.com/photo-1561557944-6e7860d1a7eb?w=400&h=250&fit=crop","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/video-friday-robot-hand-artificial-muscles","video":"https://www.youtube.com/watch?v=LikxFZZO2sk","tags":["يد روبوتية","عضلات اصطناعية","قبضة"],"timestamp":"2026-03-06T16:00:05Z"}]};

window.__NEWS_DATA_LOCALES__["ar-SA"]["2026-04-03"] = {"date":"2026-04-03","featured":{"id":"featured-0403","title":"FedEx وBerkshire Gray تتشاركان لنشر روبوتات الفرز المعتمدة على الذكاء الاصطناعي عبر شبكتهما الأمريكية الكاملة","summary":"أعلنت FedEx عن شراكة واسعة النطاق مع Berkshire Gray لنشر روبوتات الفرز والمناولة المدعومة بالذكاء الاصطناعي في جميع مرافقها الـ650 في الولايات المتحدة على مدى السنوات الثلاث القادمة. وتُقدَّر قيمة الصفقة بنحو 1.2 مليار دولار، مما يجعلها أكبر عقد أتمتة روبوتية في تاريخ قطاع اللوجستيات.","image":"https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=1200&h=600&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/31/fedex-chooses-partnerships-over-proprietary-tech-for-its-automation-strategy/","tags":["FedEx","لوجستيات","أتمتة","Berkshire Gray"],"timestamp":"2026-03-31T15:46:50Z"},"articles":[{"id":"0403-001","title":"روبوتات الـDNA قادرة على توصيل الأدوية ومطاردة الفيروسات داخل جسم الإنسان","summary":"تبرز النانوروبوتات المبرمجة بالـDNA باعتبارها الحدود التالية في الطب الموجَّه. ومن خلال الاستعارة من مفاهيم الحركة والإحساس والحمولة في الروبوتيات الكبيرة، ابتكر الباحثون آلات جزيئية قادرة على التنقل عبر مجرى الدم وإيصال الأدوية مباشرةً إلى الخلايا السرطانية.","image":"https://images.unsplash.com/photo-1576086213369-97a306d36557?w=400&h=250&fit=crop","source":"ScienceDaily","url":"https://www.sciencedaily.com/releases/2026/03/260331001104.htm","tags":["نانوروبوتات","توصيل الأدوية","DNA","طبي"],"timestamp":"2026-03-31T07:16:58Z"},{"id":"0403-002","title":"إطار تحكم جديد يُمكّن الروبوتات المرنة من التنقل في الفراغات الضيقة بحوسبة أقل","summary":"يُقلّل إطار التحكم الحركي الجديد من حسابات تخطيط المسار للروبوتات اللينة والمستمرة بنسبة 80%، مما يُتيح التنقل في الوقت الفعلي داخل الأنابيب والقنوات والممرات البيولوجية. ويُمثّل هذا العمل خطوة محورية نحو توظيف الروبوتات المرنة في الجراحة وفحص البنية التحتية.","image":"https://images.unsplash.com/photo-1555255707-c07966088b7b?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-framework-flexible-robots-tight-spaces.html","tags":["روبوتيات لينة","تخطيط المسار","جراحة"],"timestamp":"2026-03-31T17:40:06Z"},{"id":"0403-003","title":"Nomadic تجمع 8.4 مليون دولار لتحويل لقطات الروبوتات إلى بيانات تدريب للذكاء الاصطناعي قابلة للبحث","summary":"جمعت Nomadic 8.4 مليون دولار لبناء بنية تحتية تُحوّل تدفقات البيانات الخام من أجهزة الاستشعار في الروبوتات والمركبات ذاتية القيادة إلى مجموعات بيانات نظيفة ومُصنَّفة وقابلة للبحث. ويعالج خط أنابيب التعلم العميق لدى الشركة اللقطات الخام بسرعة أعلى 50 مرة مقارنةً بفرق التعليق اليدوي.","image":"https://images.unsplash.com/photo-1677442136019-21780ecad995?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/31/nomadic-raises-8-4-million-to-wrangle-the-data-pouring-off-avs/","tags":["شركة ناشئة","بيانات","تدريب","مركبات ذاتية القيادة"],"timestamp":"2026-03-31T15:00:00Z"},{"id":"0403-004","title":"مستشعرات الروبوتات قد تمنح الروبوتات حاسة لمس شبيهة بالإنسان — بحث Penn State","summary":"يعمل باحثو Penn State على تطوير مستشعرات ضغط مرنة قادرة على الكشف في آنٍ واحد عن الملمس ودرجة الحرارة والقوة بحساسية مماثلة لأطراف أصابع الإنسان. وتستخدم هذه المستشعرات مادة مركبة كهروضغطية جديدة تحافظ على أدائها بعد آلاف دورات الانحناء.","image":"https://images.unsplash.com/photo-1561557944-6e7860d1a7eb?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-qa-robots-sensors.html","tags":["مستشعرات لمسية","Penn State","روبوتيات لينة"],"timestamp":"2026-03-30T17:00:04Z"},{"id":"0403-005","title":"نقل المهارات بين الأجسام المختلفة: روبوتات ذات أجسام متباينة باتت قادرة على تبادل المعرفة","summary":"طوّر باحثو Stanford إطاراً يُتيح للروبوتات ذات التصميمات الجسدية المختلفة جوهرياً — أذرع وأرجل وعجلات — تبادل مهارات المناولة بترميزها كـ'متجهات نوايا' مجردة مستقلة عن أي شكل جسدي بعينه.","image":"https://images.unsplash.com/photo-1535378917042-10a22c95931a?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-robots-bodies-skills-intention-based.html","tags":["التعلم التحويلي","Cross-Embodiment","Stanford"],"timestamp":"2026-03-30T13:20:04Z"},{"id":"0403-006","title":"HEAPGrasp يحقق معدل نجاح 97.3% على الأجسام الجديدة في اختبارات المستودعات","summary":"يجمع نظام HEAPGrasp بين الإمساك الهرمي والتغذية الراجعة اللمسية الفورية، محققاً معدل نجاح 97.3% على أجسام لم يصادفها من قبل، تشمل التغليف شديد التشوه والمنتجات الزلقة والقطع الصناعية ذات الأشكال الغريبة.","image":"https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-heapgrasp-faster-smarter-robots-tricky.html","tags":["إمساك","لوجستيات","مناولة"],"timestamp":"2026-03-30T11:20:03Z"},{"id":"0403-007","title":"HomeTask-3000: الاختبار المرجعي الأكثر صرامة لروبوتات المنازل حتى الآن","summary":"أصدر اتحاد مؤلف من 12 جامعة اختباراً مرجعياً بعنوان HomeTask-3000 يضم 3,000 سيناريو متعدد الخطوات للأعمال المنزلية عبر 47 تصميماً واقعياً للمنازل. ويكشف الاختبار عن فجوات كبيرة في أداء روبوتات المنازل الحالية، ولا سيما في المهام التي تستلزم الاحتفاظ بالسياق لأيام متعددة.","image":"https://images.unsplash.com/photo-1527430253228-e93688616381?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-ai-benchmark-robots-chores-real.html","tags":["اختبار مرجعي","روبوتات المنازل","بحث علمي"],"timestamp":"2026-03-29T11:30:02Z"},{"id":"0403-008","title":"ميكروروبوتات دقيقة مطبوعة بتقنية 3D تسبح كالحيوانات بفضل شكلها الفيزيائي وحده","summary":"تستطيع ميكروروبوتات مجهرية مطبوعة بتقنية 3D طوّرتها Leiden University التنقل والاستجابة للتدرجات البيئية دون أجهزة استشعار أو معالجات أو بطاريات، معتمدةً كلياً على الهندسة الجسدية لأجسامها في تفاعلها مع السائل المحيط. ويفتح هذا النهج الباب أمام فئات جديدة كلياً من الميكروروبوتات الرخيصة والقابلة للتخلص منها.","image":"https://images.unsplash.com/photo-1563207153-f403bf289096?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-alive-tiny-3d-robots-animals.html","tags":["ميكروروبوتات","طباعة ثلاثية الأبعاد","حركة سلبية"],"timestamp":"2026-03-27T09:40:04Z"},{"id":"0403-009","title":"التوائم الرقمية تساعد روبوتات الإنقاذ على رسم خرائط مواقع الكوارث بسرعة أعلى 10 أضعاف","summary":"تُمكّن خوارزميات معالجة السحابة النقطية ثلاثية الأبعاد في الوقت الفعلي روبوتات الاستجابة للكوارث من بناء خرائط توأم رقمية دقيقة للمباني المنهارة في غضون ثوانٍ، مما يُتيح لها التخطيط لمسارات آمنة نحو الناجين المحاصرين بسرعة تفوق بكثير مناهج SLAM السابقة.","image":"https://images.unsplash.com/photo-1518770660439-4636190af475?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-digital-twins-robots-faster-3d.html","tags":["الاستجابة للكوارث","رسم الخرائط ثلاثي الأبعاد","SLAM"],"timestamp":"2026-03-26T15:50:01Z"},{"id":"0403-010","title":"نموذج العالم بالانتشار المرئي من Harvard يُتيح للروبوتات التخيّل قبل التصرف","summary":"تستخدم بنية ذكاء اصطناعي جديدة من Harvard نموذج انتشار مرئي كـ'محرك خيال' داخلي، مما يُمكّن الروبوتات من محاكاة نتيجة مئات الإجراءات المحتملة ذهنياً قبل تنفيذ أفضلها. ويحقق هذا النهج أداءً بشرياً في 23 من أصل 30 اختباراً مرجعياً معيارياً للمناولة.","image":"https://images.unsplash.com/photo-1677442136019-21780ecad995?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-video-based-ai-robots-visual.html","tags":["نموذج العالم","الانتشار","Harvard","تخطيط"],"timestamp":"2026-03-26T10:20:03Z"},{"id":"0403-011","title":"التعلم المعزز متعدد العوامل يُقلّص اختناقات روبوتات المستودعات ويرفع الإنتاجية 25%","summary":"رفع نظام التعلم المعزز الديناميكي متعدد العوامل المنتشر في مركز توزيع Amazon المحاكى بـ500 روبوت إنتاجية الطلبات بنسبة 25%، وذلك بإعادة توجيه الروبوتات استباقياً حول نقاط الازدحام المتوقعة قبل تشكّل الاختناقات بدلاً من التفاعل بعد وقوعها.","image":"https://images.unsplash.com/photo-1531746790731-6c087fecd65a?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-ai-warehouse-robot-traffic-boosting.html","tags":["مستودع","MARL","Amazon","إنتاجية"],"timestamp":"2026-03-26T09:30:01Z"},{"id":"0403-012","title":"طائرات مسيّرة مستوحاة من الخفافيش تتنقل في مواقع الحرائق صفرية الرؤية باستخدام الموجات فوق الصوتية","summary":"تتنقل الطائرة المسيّرة المستوحاة من الخفافيش التابعة لـWPI في بيئات الدخان الكثيف وانعدام الرؤية باستخدام نظام تحديد الموقع بالصدى بالموجات فوق الصوتية وذكاء اصطناعي مخصص يفسّر الإشارات المنعكسة كخريطة ثلاثية الأبعاد. وتجري إدارات الإطفاء حالياً تجريب النظام في مهام الاستطلاع للمستجيبين الأوائل.","image":"https://images.unsplash.com/photo-1527430253228-e93688616381?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-ultrasound-palm-sized-drones-fog.html","tags":["طائرات مسيّرة","الاستجابة للحرائق","موجات فوق صوتية","ملاحة"],"timestamp":"2026-03-26T09:06:49Z"},{"id":"0403-013","title":"يد روبوتية بسبيكة ذاكرة الشكل بلا محرك أخف بـ70% من التصاميم المعتمدة على المحركات المؤازِرة","summary":"بالاستعاضة عن محركات المؤازِرة الكهربائية بأسلاك سبيكة ذاكرة الشكل وناقل حركة ميكانيكي ذكي، أنجز الباحثون يداً روبوتية خماسية الأصابع لا يتجاوز وزنها 180 جراماً، أي أخف بـ70% من التصاميم المماثلة ذات المحركات المؤازِرة، مع الحفاظ على سرعات تشغيل تقل عن 100 ميلي ثانية.","image":"https://images.unsplash.com/photo-1561557944-6e7860d1a7eb?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-robotic-motors-shifting-actuator.html","tags":["يد روبوتية","SMA","خفة الوزن","أطراف اصطناعية"],"timestamp":"2026-03-25T10:00:04Z"},{"id":"0403-014","title":"يد اصطناعية تُتحكم بها عبر سوار يد تمنح مبتوري الأطراف تحكماً منفرداً بكل إصبع","summary":"يقرأ سوار EMG الصادر عن MIT الإشارات العضلية لتوفير تحكم لحظي بكل إصبع في يد اصطناعية على حدة. ويتمكن المستخدمون من التحكم المستقل الموثوق بالأصابع خلال أقل من 20 ساعة تدريب، مقارنةً بـ200 ساعة أو أكثر تستلزمها الأطراف الاصطناعية العضلية الكهربائية التقليدية.","image":"https://images.unsplash.com/photo-1576086213369-97a306d36557?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-wristband-enables-wearers-robotic-movements.html","tags":["أطراف اصطناعية","EMG","MIT","إمكانية الوصول"],"timestamp":"2026-03-25T06:00:09Z"},{"id":"0403-015","title":"روبوت قطف الطماطم يتعلم الحصاد وفق درجة الصعوبة ويُحسّن الغلة 35%","summary":"بدلاً من قطف الطماطم بالترتيب الذي يصادفها، يتنبأ روبوت زراعي جديد بصعوبة الحصاد بناءً على موضع الثمرة وحجب الرؤية واتجاه الساق، ثم يُعطي الأولوية للأهداف الأسهل. وقد حسّنت هذه الاستراتيجية إجمالي غلة الحصاد بنسبة 35% في تجارب الدفيئة الخاضعة للتحكم.","image":"https://images.unsplash.com/photo-1531746790731-6c087fecd65a?w=400&h=250&fit=crop","source":"ScienceDaily","url":"https://www.sciencedaily.com/releases/2026/03/260317064512.htm","tags":["روبوتيات زراعية","طماطم","تخطيط بالذكاء الاصطناعي"],"timestamp":"2026-03-18T00:26:44Z"},{"id":"0403-016","title":"طائرة BRINC Guardian المسيّرة: مستجيب شرطي للطوارئ يحمل Narcan ويطارد السيارات","summary":"كشفت BRINC عن طائرة Guardian المسيّرة المصمَّمة لسرعة الاستجابة لنداءات الطوارئ 911. تتكامل فيها اتصالات Starlink لتغطية وطنية، وقادرة على نشر Narcan في مكالمات الجرعات الزائدة، وتطارد المشتبه بهم بسرعة 60 ميلاً في الساعة. وقد أبدى المدافعون عن الحريات المدنية قلقاً بالغاً إزاء هذا النظام.","image":"https://images.unsplash.com/photo-1529612700005-e35377bf1415?w=400&h=250&fit=crop","source":"Ars Technica","url":"https://arstechnica.com/gadgets/2026/03/brincs-new-police-drone-uses-starlink-carries-narcan-chases-vehicles-at-60mph/","tags":["شرطة","طائرة مسيّرة","BRINC","طوارئ"],"timestamp":"2026-03-25T21:12:03Z"},{"id":"0403-017","title":"أستراليا تنشر روبوتات لفحص مزارع الطاقة الشمسية في حرارة الأراضي الداخلية القصوى","summary":"تحلّ روبوتات الفحص المدعومة بالذكاء الاصطناعي محل أعمال الصيانة البشرية الخطرة في أكبر مزارع الطاقة الشمسية في أستراليا، إذ تجتاز كيلومترات من التضاريس الصحراوية الوعرة في درجات حرارة 50 درجة مئوية لتنظيف الألواح وقياس الكفاءة ورصد الأعطال بالكاميرات الحرارية.","image":"https://images.unsplash.com/photo-1545987796-200677ee1011?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-robots-humans-biggest-solar-farms.html","tags":["طاقة شمسية","أستراليا","فحص","صناعي"],"timestamp":"2026-03-25T18:10:07Z"},{"id":"0403-018","title":"طائرات مسيّرة للبحث والإنقاذ بذكاء اصطناعي تعثر على المفقودين بسرعة أعلى 4 أضعاف مقارنةً بالفرق البرية","summary":"عثرت منصة طائرات مسيّرة متعددة الاستشعار تدمج الكاميرات الحرارية والأشعة تحت الحمراء والمرئية مع نظام كشف بالذكاء الاصطناعي على المفقودين في الأماكن البرية أربع مرات أسرع من فرق البحث البرية منفردةً. وتتبنى هذا النظام منظمات الإنقاذ الجبلي في سويسرا وكولورادو.","image":"https://images.unsplash.com/photo-1527430253228-e93688616381?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-drones-paired-ai-searchandrescue-teams.html","tags":["بحث وإنقاذ","طائرات مسيّرة","حرارية","طوارئ"],"timestamp":"2026-03-24T14:20:05Z"},{"id":"0403-019","title":"Amazon تستحوذ على Fauna Robotics: الإنسان الآلي Sprout مصمَّم للمنازل والمستشفيات","summary":"يُضيف استحواذ Amazon على Fauna Robotics روبوت Sprout الإنساني بحجم الطفل والمركّز على التفاعل الاجتماعي إلى عائلة Amazon. صُمِّم Sprout للعمل في البيئات غير المنظمة كغرف المعيشة وممرات المستشفيات، مُكمِّلاً أسطول روبوتات المستودعات الحالي لدى Amazon.","image":"https://images.unsplash.com/photo-1620712943543-bcc4688e7485?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-amazon-buys-fauna-robotics-maker.html","tags":["Amazon","روبوت إنساني","روبوتات المنازل","رعاية صحية"],"timestamp":"2026-03-25T05:30:01Z"},{"id":"0403-020","title":"سرب Georgia Tech بلا إلكترونيات: روبوتات ميكانيكية تنظّم نفسها بنفسها","summary":"أثبت باحثو Georgia Tech قدرة سرب من الروبوتات الميكانيكية البحتة — بلا مستشعرات ولا معالجات ولا بطاريات — على تحقيق سلوك جماعي منظّم ذاتياً من خلال تفاعلات الشكل الجسدي. ويطعن هذا العمل في الافتراضات الأساسية حول ما يستلزمه ذكاء الأسراب.","image":"https://images.unsplash.com/photo-1518770660439-4636190af475?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-04-robotic-swarm-electronics-batteries-brains.html","tags":["سرب","Georgia Tech","ميكانيكي","تنظيم ذاتي"],"timestamp":"2026-04-01T10:00:02Z"},{"id":"0403-021","title":"روبوتات ROS التي تتحكم بها نماذج LLM تستجيب للأوامر بالإنجليزية البسيطة في الوقت الفعلي","summary":"تدمج طبقة وسيطة جديدة نماذج لغوية بمستوى GPT-4 مع نظام Robot Operating System، مما يُتيح للمهندسين وغير المتخصصين على حدٍّ سواء إصدار أوامر سلوكيات روبوتية معقدة متعددة الخطوات باللغة الطبيعية. وقد تم التحقق من صحة النظام على خمس منصات روبوتية مختلفة.","image":"https://images.unsplash.com/photo-1677442136019-21780ecad995?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-combining-robot-llms-natural-language.html","tags":["LLM","ROS","لغة طبيعية","تحكم"],"timestamp":"2026-04-01T08:10:01Z"}]};

window.__NEWS_DATA_LOCALES__["ar-SA"]["2026-04-02"] = {"date":"2026-04-02","featured":{"id":"featured-0402","title":"نموذج π0 الأساسي من Physical Intelligence: أكثر أدمغة الروبوتات العامة قدرةً حتى الآن","summary":"يُشار إلى أن النموذج الأساسي π0 الصادر عن Physical Intelligence، القادر على التحكم في أنواع متعددة من الروبوتات دون ضبط دقيق خاص بكل مهمة، يخضع حالياً للترخيص من قِبل ستة من كبار مصنّعي الروبوتات الأصليين، فيما تستعد الشركة لجولة تمويل بمليار دولار. تُظهر النتائج الأولية أن النموذج يتعميم على مهام جديدة بأقل من 100 عرض توضيحي.","image":"https://images.unsplash.com/photo-1535378917042-10a22c95931a?w=1200&h=600&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/27/physical-intelligence-is-reportedly-in-talks-to-raise-1-billion-again/","tags":["Physical Intelligence","نموذج أساسي","تمويل"],"timestamp":"2026-03-27T23:59:40Z"},"articles":[{"id":"0402-001","title":"Amazon تستحوذ على Fauna Robotics صانعة الروبوت الآدمي Sprout بحجم الطفل","summary":"يُمثّل هذا الاستحواذ الثاني لـ Amazon في مجال الروبوتات خلال شهر واحد، إذ تُضم Fauna Robotics وروبوتها الآدمي Sprout إلى محفظتها. صُمّم Sprout ليكون رفيقاً اجتماعياً في المنازل والمستشفيات، ويعمل بأمان في محيط الأطفال وكبار السن بفضل نظامه المتقدم لتفادي الاصطدامات وقدرته التعبيرية في التواصل.","image":"https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/24/amazon-just-bought-a-startup-making-kid-size-humanoid-robots/","tags":["Amazon","Fauna Robotics","استحواذ","روبوت آدمي"],"timestamp":"2026-03-25T00:53:39Z"},{"id":"0402-002","title":"Agile Robots تتشارك مع Google DeepMind: بيانات للنماذج الأساسية، ونماذج للأجهزة","summary":"في إطار شراكة ذات منفعة متبادلة، ستجمع Agile Robots ملايين نقاط بيانات العروض التوضيحية للمهام عبر منصاتها الآدمية وتشاركها مع Google DeepMind. في المقابل، ستُدمج النماذج الأساسية للروبوتات الصادرة عن DeepMind في منصة الجيل القادم من روبوتات Agile.","image":"https://images.unsplash.com/photo-1555255707-c07966088b7b?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/24/agile-robots-becomes-the-latest-robotics-company-to-partner-with-google-deepmind/","tags":["Agile Robots","Google DeepMind","شراكة"],"timestamp":"2026-03-24T12:05:00Z"},{"id":"0402-003","title":"حرب الطائرات المسيّرة المستقلة في أوكرانيا تُعيد تشكيل ملامح النزاعات العسكرية","summary":"يُنشر كلا الجانبين في النزاع الأوكراني آلاف الطائرات المسيّرة المستقلة المدعومة بالذكاء الاصطناعي أسبوعياً. تجاوزت وتيرة التطور التكنولوجي القانون الدولي، محذّراً الخبراء من أن الرقابة البشرية الفعّالة تتآكل مع تقلّص نطاق المواجهات المستقلة إلى ثوانٍ معدودة.","image":"https://images.unsplash.com/photo-1527430253228-e93688616381?w=400&h=250&fit=crop","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/autonomous-drone-warfare","tags":["عسكري","طائرات مسيّرة","أوكرانيا","أخلاقيات الذكاء الاصطناعي"],"timestamp":"2026-03-24T13:00:05Z"},{"id":"0402-004","title":"طائرة مسيّرة للبحث والإنقاذ بذكاء اصطناعي حراري تعثر على المشاة المفقودين أسرع بأربع مرات","summary":"بالتعاون مع فرق الإنقاذ الجبلي السويسرية، رصدت طائرة مسيّرة جديدة متعددة المستشعرات تجمع بين كاميرات حرارية وأشعة تحت الحمراء وكاميرات ملونة مع محرك كشف بالذكاء الاصطناعي مشاةً مفقودين بسرعة تفوق البحث الأرضي التقليدي أربع مرات في ظروف جبلية ألبية محاكاة.","image":"https://images.unsplash.com/photo-1527430253228-e93688616381?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-drones-paired-ai-searchandrescue-teams.html","tags":["بحث وإنقاذ","طائرات مسيّرة","إنقاذ جبلي","تصوير حراري"],"timestamp":"2026-03-24T14:20:05Z"},{"id":"0402-005","title":"مستويات قدرة الروبوت الآدمي من Fraunhofer: معيار جديد لتقييم استقلالية الروبوتات","summary":"نشر معهد Fraunhofer HNFIZ نظام تصنيف خماسي المستويات لقدرات الروبوتات الآدمية، يشمل التنقل والتلاعب والاستقلالية المعرفية. يوفر هذا الإطار للمصنّعين والجهات التنظيمية والعملاء لغةً مشتركة لمقارنة الأنظمة الآدمية.","image":"https://images.unsplash.com/photo-1620712943543-bcc4688e7485?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-humanoid-robots-mobility-cognition.html","tags":["روبوت آدمي","معايير","Fraunhofer","استقلالية"],"timestamp":"2026-03-23T17:20:07Z"},{"id":"0402-006","title":"روبوت Rutgers الشبيه بالطيور يتفوق على الطائرات المسيّرة في كفاءة الطاقة بأجنحته المرنة","summary":"يُحقق روبوت الرفرفة من Rutgers كفاءة طاقة أعلى ثلاث مرات من الطائرات المسيّرة رباعية الدوارة المكافئة عند سرعات أقل من 5 م/ث، وذلك باستخدام أجنحة مفصلية تتكيف مع الرياح في الوقت الفعلي. تجعله خصائصه الديناميكية الهوائية الفريدة فعّالاً بشكل خاص لمراقبة الحياة البرية في الغابات الكثيفة.","image":"https://images.unsplash.com/photo-1529612700005-e35377bf1415?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-birdlike-robots-greater-flexibility-drones.html","tags":["روبوت رفرفة","Rutgers","مستوحى من الطبيعة","كفاءة الطاقة"],"timestamp":"2026-03-23T13:20:02Z"},{"id":"0402-007","title":"روبوت تتبّع الروائح يُحدّد تسريبات الغاز والمتفجرات بحساس واحد معطوب","summary":"يحافظ روبوت شمّي مستوحى من الطبيعة، مُصمَّم للكشف عن تسريبات الغاز وتحديد مواقع المتفجرات، على عمله الموثوق حتى عند عطل أحد صفيفيْ مستشعراته. يستوحي هذا التصميم المتحمّل للأعطال الطريقةَ التي تواصل بها الحشرات تتبّع الروائح بعد فقدان إحدى قرنيْ استشعارها.","image":"https://images.unsplash.com/photo-1545987796-200677ee1011?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-insect-robot-tracks-odors-antenna.html","tags":["حسّ شمّي","سلامة","كشف الغاز","تحمّل الأعطال"],"timestamp":"2026-03-23T12:00:03Z"},{"id":"0402-008","title":"روبوتات مُدرِّسة في مدارس شيكاغو تُعلِّم التعاطف دون ادّعاء الإنسانية","summary":"تستخدم تجربة أُجريت في 12 مدرسة ابتدائية بشيكاغو روبوتات ذات مساعدة اجتماعية لتعليم مهارات التعلم الاجتماعي العاطفي. والأهم أن الروبوتات تُفصح صراحةً عن كونها آلات، وتُبيّن الأبحاث أن هذا الصدق يُحسِّن نتائج التعلم فعلياً مقارنةً بالروبوتات المُشبَّهة بالبشر.","image":"https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-chicago-robot-sel-effectively-human.html","tags":["تعليم","التعلم الاجتماعي العاطفي","روبوتات اجتماعية","أخلاقيات"],"timestamp":"2026-03-20T06:10:01Z"},{"id":"0402-009","title":"WANDER-Bot: روبوت يعمل بطاقة الرياح لمراقبة البيئات القاسية باستمرار","summary":"يعتمد WANDER-bot من Cranfield University على طاقة الرياح لتشغيل حركته ومستشعراته، مما يُتيح له العمل الذاتي غير المحدود في الصحاري والتندرا والتضاريس البركانية. قد يُتيح هذا التصميم المطبوع ثلاثي الأبعاد بتكلفة 200 دولار إنشاء شبكات مراقبة بيئية على نطاق قاري.","image":"https://images.unsplash.com/photo-1545987796-200677ee1011?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-powered-robot-enable-term-exploration.html","tags":["طاقة الرياح","البيئة","استكشاف","Cranfield"],"timestamp":"2026-03-19T16:20:03Z"},{"id":"0402-010","title":"روبوتات تتعلم أسرع من معلميها البشر — اختراق جديد في التعلم بالمحاكاة","summary":"يُحدّد إطار جديد للتعلم بالمحاكاة المعجّل أوجه القصور في العروض التوضيحية البشرية ويُحسّنها، مما يُمكّن الروبوتات من أداء المهام المكتسبة بسرعة تفوق البشر المُظاهِرين بنسبة 30% بعد 10 جلسات تدريبية فحسب.","image":"https://images.unsplash.com/photo-1677442136019-21780ecad995?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-smarter-faster-human-ai-robots.html","tags":["التعلم بالمحاكاة","تعلّم الروبوتات","كفاءة"],"timestamp":"2026-03-19T14:20:06Z"},{"id":"0402-011","title":"Gecko Robotics تفوز بأكبر عقد روبوتات للبحرية الأمريكية لفحص الأسطول بأكمله","summary":"منحت البحرية Gecko Robotics عقداً لخمس سنوات لنشر روبوتات تفتيش متسلقة للجدران على كل فئة من السفن. تستخدم الروبوتات أجهزة استشعار بالموجات فوق الصوتية والأشعة تحت الحمراء والمستشعرات البصرية لمراقبة سلامة البدن وجودة اللحامات والتآكل باستمرار، مع بناء نماذج للصيانة التنبؤية.","image":"https://images.unsplash.com/photo-1542744173-8e7e53415bb0?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/17/gecko-robotics-lands-the-largest-u-s-navy-robotics-deal-yet/","tags":["بحرية","تفتيش","عسكري","Gecko Robotics"],"timestamp":"2026-03-17T10:00:00Z"},{"id":"0402-012","title":"عطل روبوت مطعم Haidilao يتحول إلى حدث فيروسي: AgiBot يرقص بلا سيطرة","summary":"حصد مقطع لروبوت نادل آدمي من AgiBot يفقد السيطرة ويرقص بشكل عشوائي في مطعم هوت بوت Haidilao في كوبرتينو أكثر من 40 مليون مشاهدة. نسبت الشركة العطل إلى حالة حافة في تحديث برمجي، وأطلقت منذ ذلك الحين رقعة تحديث على مستوى النظام بأكمله.","image":"https://images.unsplash.com/photo-1620712943543-bcc4688e7485?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/19/restaurant-dancing-robot-went-wild-hot-pot-cupertino-haidilao-agibot/","tags":["AgiBot","مطعم","فيروسي","عطل"],"timestamp":"2026-03-19T21:13:50Z"},{"id":"0402-013","title":"RJ Scaringe من Rivian: أوقفوا بناء الروبوتات الآدمية وابنوا آلات ذات أغراض محددة","summary":"يرى الرئيس التنفيذي لـ Rivian ومؤسس Mind Robotics، RJ Scaringe، أن صناعة الروبوتات ترتكب خطأً جوهرياً بمطاردة روبوتات على شكل إنسان لمهام المصانع. تصمّم شركته الجديدة الروبوتات تحديداً لتتناسب مع مهامها المقصودة، لا مع تشريح الجسم البشري.","image":"https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/15/rivians-rj-scaringe-thinks-were-doing-robots-all-wrong/","tags":["Mind Robotics","Rivian","صناعي","رأي"],"timestamp":"2026-03-15T14:30:00Z"},{"id":"0402-014","title":"Mind Robotics تجمع 500 مليون دولار لروبوتات مصنعية مُدرَّبة على خط إنتاج Rivian ذاته","summary":"جمعت Mind Robotics المنبثقة عن Rivian 500 مليون دولار لبناء ونشر روبوتات صناعية مدعومة بالذكاء الاصطناعي مُدرَّبة مباشرةً في مصنع Rivian العملاق. تتمتع الشركة الناشئة بوصول حصري إلى تيرابايتات من بيانات العروض التوضيحية للمصنع، مما يُشكّل ميزة تنافسية بالغة الأهمية.","image":"https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/11/rivian-mind-robotics-series-a-500m-fund-raise-industrial-ai-powered-robots/","tags":["Rivian","شركة ناشئة","صناعي","تمويل"],"timestamp":"2026-03-11T16:12:02Z"},{"id":"0402-015","title":"شرائح Qualcomm IQ10 تُشغّل دماغ الجيل القادم من روبوتات Neura Robotics الآدمية","summary":"تبني Neura Robotics منصتها الآدمية الجديدة حول معالج الذكاء الاصطناعي IQ10 من Qualcomm، الذي يوفر 40 TOPS من قدرة الاستدلال على الجهاز بأقل من 20 واط. تُشكّل هذه الشراكة تحدياً لهيمنة Nvidia على سوق منصات الحوسبة الروبوتية.","image":"https://images.unsplash.com/photo-1535378917042-10a22c95931a?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/09/qualcomms-partnership-with-neura-robotics-is-just-the-beginning/","tags":["Qualcomm","Neura Robotics","شرائح","أجهزة"],"timestamp":"2026-03-09T15:58:11Z"},{"id":"0402-016","title":"مزرعة Canopii الروبوتية المستقلة تُنتج 40,000 رطل من الأعشاب سنوياً في مساحة ملعب كرة سلة","summary":"تستخدم Canopii منظومةً متكاملة رأسياً من الروبوتات المخصصة — البذر والري والمراقبة والحصاد — لتشغيل مزرعة داخلية مستقلة كلياً. وخلافاً للسابقين الذين أخفقوا بسبب تكاليف العمالة، يُحقق نهج Canopii الروبوتي الكامل الربحية بنصف تكلفة المزارع الداخلية التقليدية.","image":"https://images.unsplash.com/photo-1531746790731-6c087fecd65a?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/11/canopii-looks-to-succeed-where-past-indoor-farms-have-not/","tags":["الروبوتات الزراعية","الزراعة الداخلية","مستقل"],"timestamp":"2026-03-11T14:00:00Z"},{"id":"0402-017","title":"Intrinsic تنضم إلى Google: Alphabet تُوحّد منصتها البرمجية للروبوتات","summary":"بعد خمس سنوات بوصفها شركة مستقلة تابعة لـ Alphabet، تُدمج شركة البرمجيات الروبوتية Intrinsic في Google. يُوحّد هذا الخطوة أصول Alphabet الروبوتية تحت سقف واحد ويُشير إلى نية Google في بناء منصة روبوتية موحّدة تجمع البرمجيات ونماذج الذكاء الاصطناعي وشراكات الأجهزة.","image":"https://images.unsplash.com/photo-1555255707-c07966088b7b?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/02/25/alphabet-owned-robotics-software-company-intrinsic-joins-google/","tags":["Google","Intrinsic","Alphabet","برمجيات"],"timestamp":"2026-02-25T20:00:00Z"},{"id":"0402-018","title":"صناعة الروبوتات الآدمية الصينية تتقدم على الغرب في النشر التجاري","summary":"يُظهر تحليل مُفصّل أجراه TechCrunch أن مصنّعي الروبوتات الآدمية الصينيين شحنوا تجارياً خلال الـ12 شهراً الماضية وحدات أكثر مما شحنته جميع شركات الغرب مجتمعةً، مدفوعين بتكاليف تصنيع أقل ودورات تطوير أسرع ودعم حكومي ضخم.","image":"https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/02/28/why-chinas-humanoid-robot-industry-is-winning-the-early-market/","tags":["الصين","روبوت آدمي","سوق","منافسة"],"timestamp":"2026-02-28T15:00:00Z"},{"id":"0402-019","title":"تقييم Anduril بـ60 مليار دولار: شركة روبوتات الدفاع الناشئة تنمو أسرع من أي شركة أسلحة في التاريخ","summary":"تستهدف Anduril Industries تقييماً بـ60 مليار دولار في جولة تمويلها القادمة، مما يجعلها أعلى شركة تقنية دفاعية قيمةً في التاريخ من حيث سرعة نمو التقييم. تضاعفت إيراداتها من أسراب الطائرات المسيّرة المستقلة والمركبات تحت الماء وأنظمة المراقبة بالذكاء الاصطناعي ثلاث مرات في 18 شهراً.","image":"https://images.unsplash.com/photo-1542744173-8e7e53415bb0?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/03/anduril-aims-at-60-billion-valuation-in-new-funding-round/","tags":["Anduril","دفاع","تمويل","طائرات مسيّرة"],"timestamp":"2026-03-03T20:06:45Z"},{"id":"0402-020","title":"30 عاماً من الروبوتات المشية: كيف غيّر Honda P2 كل شيء","summary":"صنّف IEEE روبوت Honda P2 — أول روبوت ثنائي القدمين مكتفٍ بذاته حقاً — معلماً رسمياً لـ IEEE، بعد 30 عاماً من الكشف عنه. خوارزمية المشي الديناميكية لـ P2، التي طوّرها المهندس Masato Hirose، هي السلف المباشر لكل روبوت مشي تقريباً تم تطويره منذ ذلك الحين.","image":"https://images.unsplash.com/photo-1485827404703-89b55fcc595e?w=400&h=250&fit=crop","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/honda-p2-robot-ieee-milestone","tags":["Honda","تاريخ","ثنائي القدمين","IEEE"],"timestamp":"2026-03-25T18:00:05Z"},{"id":"0402-021","title":"Amazon تستحوذ على Rivr: روبوت تسلق الدرج يُقرّب التوصيل حتى عتبة الباب","summary":"يُمثّل استحواذ Amazon على Rivr، صانعة روبوت بعجلات يستطيع تسلق الدرج باستقلالية والتنقل في مداخل المباني، أولَ استثمار جاد للشركة في توصيل الميل الأخير. قد تُمكّن هذه التقنية في نهاية المطاف من توصيل الطرود إلى أي طابق في أي مبنى.","image":"https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/19/amazon-acquires-rivr-maker-of-a-stair-climbing-delivery-robot/","tags":["Amazon","توصيل","استحواذ","الميل الأخير"],"timestamp":"2026-03-19T23:28:37Z"}]};

window.__NEWS_DATA_LOCALES__["ar-SA"]["2026-04-01"] = {"date":"2026-04-01","featured":{"id":"featured-0401","title":"Amazon تستحوذ على شركتَي روبوتات ناشئتَين في شهر واحد: Rivr و Fauna Robotics","summary":"أتمّت Amazon استحواذها على كلٍّ من Rivr (روبوت توصيل يصعد الدرج) و Fauna Robotics (الروبوت الاجتماعي الإنساني بحجم طفل «Sprout») في الشهر ذاته، في إشارة إلى توسّعها العدواني من أتمتة المستودعات البحتة نحو المنازل وتوصيل الميل الأخير. يُقدّر المحللون القيمة المجمّعة للصفقتين بأكثر من 400 مليون دولار.","image":"https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=1200&h=600&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/24/amazon-just-bought-a-startup-making-kid-size-humanoid-robots/","tags":["Amazon","استحواذ","استراتيجية","روبوت إنساني"],"timestamp":"2026-03-25T00:53:39Z"},"articles":[{"id":"0401-001","title":"باحثون يبنون سرباً روبوتياً بلا إلكترونيات ولا بطاريات ولا «عقول»","summary":"حقّق السرب الميكانيكي البحت الجديد من Georgia Tech سلوكاً جماعياً ناشئاً من تفاعلات الشكل المادي وحده. يتحدّى البحث الافتراضات الجوهرية في ذكاء الأسراب، ويفتح الطريق أمام تجمّعات روبوتية فائقة الرخص قابلة للانتشار الواسع لرصد البيئة.","image":"https://images.unsplash.com/photo-1563207153-f403bf289096?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-04-robotic-swarm-electronics-batteries-brains.html","tags":["سرب","Georgia Tech","ميكانيكي","ناشئ"],"timestamp":"2026-04-01T10:00:02Z"},{"id":"0401-002","title":"LLM + ROS: التحكم بالروبوتات بالغة الطبيعية أصبح واقعاً للمشغّلين غير المتخصصين","summary":"تتيح جسرة middleware جديدة من ROS إلى نماذج اللغة الكبيرة لأيّ شخص إصدار أوامر للروبوتات الصناعية بلغة طبيعية دون الحاجة إلى برمجة. يفسّر النظام التعليمات الغامضة ويطرح أسئلة توضيحية ويولّد تسلسلات أوامر آمنة في الوقت الفعلي.","image":"https://images.unsplash.com/photo-1677442136019-21780ecad995?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-combining-robot-llms-natural-language.html","tags":["LLM","ROS","لغة طبيعية","إنسان-روبوت"],"timestamp":"2026-04-01T08:10:01Z"},{"id":"0401-003","title":"إطار تحكّم روبوتي مرن يخفّض حسابات تخطيط المسار بنسبة 80% لفحص الأنابيب","summary":"يُقلّص إطار التحكّم الحركي الجديد للروبوتات اللينة والمستمرة الحوسبة بنسبة 80%، مما يُتيح الملاحة الفورية داخل الأنابيب الضيّقة والأوعية الدموية والتجاويف غير المنتظمة. جرى التحقّق من النهج في نماذج أوّلية لروبوتات التنظير وأنظمة فحص أنابيب الغاز.","image":"https://images.unsplash.com/photo-1559757148-5c350d0d3c56?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-framework-flexible-robots-tight-spaces.html","tags":["روبوتيات لينة","أنابيب","تحكّم","طبي"],"timestamp":"2026-03-31T17:40:06Z"},{"id":"0401-004","title":"نانوروبوتات الDNA: آلات جزيئية تصطاد الفيروسات وتوصّل أدوية السرطان","summary":"تُطوّر فرق هندسية في MIT و Caltech نانوروبوتات DNA قابلة للبرمجة، قادرة على تحديد أنواع خلوية بعينها والالتصاق بها وإطلاق حمولات علاجية بدقة دون الخلوية. تُظهر التجارب على الحيوانات كفاءة توصيل دواء أعلى بعشرة أضعاف مقارنةً بمقاربات الجسيمات النانوية.","image":"https://images.unsplash.com/photo-1576086213369-97a306d36557?w=400&h=250&fit=crop","source":"ScienceDaily","url":"https://www.sciencedaily.com/releases/2026/03/260331001104.htm","tags":["نانوروبوتات","طبي","سرطان","توصيل الدواء"],"timestamp":"2026-03-31T07:16:58Z"},{"id":"0401-005","title":"FedEx تُراهن بقوة على الروبوتات الشريكة: اتفاق مع Berkshire Gray يغطّي جميع منشآتها الـ650 في الولايات المتحدة","summary":"بدلاً من بناء قسم روبوتيات خاص بها، وقّعت FedEx مع Berkshire Gray لتزويد جميع منشآتها الأمريكية بروبوتات فرز وانتقاء ومعالجة طرود مدعومة بـAI. يُتوقّع أن تُلغي الشراكة متعددة السنوات 12,000 وظيفة يدوية متكررة مع تقليص أخطاء الفرز بنسبة 95%.","image":"https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/31/fedex-chooses-partnerships-over-proprietary-tech-for-its-automation-strategy/","tags":["FedEx","لوجستيات","Berkshire Gray","أتمتة"],"timestamp":"2026-03-31T15:46:50Z"},{"id":"0401-006","title":"Nomadic تحوّل مقاطع الروبوتات والمركبات ذاتية القيادة إلى مجموعات بيانات تدريب نظيفة وتجمع 8.4 مليون دولار","summary":"بتمويل جديد بلغ 8.4 مليون دولار، تبني Nomadic طبقة البنية التحتية للبيانات لعصر AI المادي: بتحويل لقطات الروبوتات والمركبات ذاتية القيادة الخام إلى مجموعات بيانات نظيفة ومُصنَّفة وقابلة للاستعلام، تُتيح للفرق تدريب النماذج وتقييمها دون تعليق يدوي.","image":"https://images.unsplash.com/photo-1535378917042-10a22c95931a?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/31/nomadic-raises-8-4-million-to-wrangle-the-data-pouring-off-avs/","tags":["شركة ناشئة","بيانات","تدريب","AI مادي"],"timestamp":"2026-03-31T15:00:00Z"},{"id":"0401-007","title":"يُقال إن Physical Intelligence في مفاوضات للحصول على مليار دولار لمضاعفة تقييمها","summary":"تجري π (Physical Intelligence) مفاوضات مع Thrive Capital و Founders Fund و Lachy Groom للحصول على جولة بمليار دولار ترفع تقييمها إلى 11.2 مليار دولار في أقل من عام. ستموّل الجولة تسويق نموذج π0 لدى شركاء تصنيع الروبوتات.","image":"https://images.unsplash.com/photo-1620712943543-bcc4688e7485?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/27/physical-intelligence-is-reportedly-in-talks-to-raise-1-billion-again/","tags":["Physical Intelligence","تمويل","نموذج أساسي"],"timestamp":"2026-03-27T23:59:40Z"},{"id":"0401-008","title":"فيديو الجمعة: روبوت Roadrunner ثنائي القدمين يبلغ 5 م/ث بنظام هجين عجلة-ساق","summary":"Roadrunner روبوت ثنائي القدمين مزوّد بعجلات قابلة للطيّ في قدميه، تُتيح له التبديل بين المشي والتدحرج بحسب التضاريس. يبلغ 5 م/ث في البيئات المستوية، ليكون من أسرع الروبوتات ذات الأرجل المُثبَّتة على الإطلاق، مع احتفاظه بقدرة تسلّق الدرج كاملة.","image":"https://images.unsplash.com/photo-1535378917042-10a22c95931a?w=400&h=250&fit=crop","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/roadrunner-bipedal-robot","video":"https://www.youtube.com/watch?v=tF4DML7FIWk","tags":["ثنائي القدمين","سرعة","ذو عجلات","حركة"],"timestamp":"2026-03-27T16:30:03Z"},{"id":"0401-009","title":"روبوتات مصغّرة مطبوعة ثلاثياً تتنقّل دون أجهزة استشعار أو برامج — فيزياء محضة","summary":"أثبتت جامعة Leiden أن روبوتات مجهرية مطبوعة بالطباعة ثلاثية الأبعاد تُحقّق السباحة الاتجاهية والملاحة باستخدام الخصائص الفيزيائية لشكلها ومادتها فقط — صفر إلكترونيات وصفر كود. قد يُتيح هذا العمل تصنيع مليارات روبوتات الاستشعار البيئي الرخيصة والقابلة للتخلّص منها.","image":"https://images.unsplash.com/photo-1563207153-f403bf289096?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-alive-tiny-3d-robots-animals.html","tags":["ميكروروبوتات","طباعة ثلاثية الأبعاد","سلبي","Leiden"],"timestamp":"2026-03-27T09:40:04Z"},{"id":"0401-010","title":"روبوتات الكوارث تحصل على خرائط أسرع: إنجاز في معالجة سُحب النقاط ثلاثية الأبعاد في الوقت الفعلي","summary":"تُتيح خوارزميات جديدة مبنية على تفاضلات الموترات المتفرّقة ومطابقة الميزات المُتعلَّمة لروبوتات الإنقاذ بناء خرائط ثلاثية الأبعاد لبيئات الكوارث بدقة أعلى وسرعة أكبر 10 أضعاف من مناهج SLAM السابقة. يعمل النظام في الوقت الفعلي على أجهزة الحافة المتاحة في منصات الروبوتات التجارية.","image":"https://images.unsplash.com/photo-1518770660439-4636190af475?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-digital-twins-robots-faster-3d.html","tags":["SLAM","رسم خرائط ثلاثي الأبعاد","كوارث","حوسبة الحافة"],"timestamp":"2026-03-26T15:50:01Z"},{"id":"0401-011","title":"AI التخيّل من Harvard: الروبوتات تُخطّط بتوليد مقاطع فيديو لمستقبلها","summary":"يُتيح نموذج العالم الجديد القائم على انتشار الفيديو من Harvard للروبوتات تخطيط المهام متعددة الخطوات بتوليد فيديو ذهني لكل تسلسل أفعال ممكن. يختار الروبوت الخطة التي يتوافق نتاجها المُتخيَّل مع هدفه على أفضل وجه، محقّقاً أداءً متقدّماً على 23 معياراً لمهام التعامل.","image":"https://images.unsplash.com/photo-1677442136019-21780ecad995?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-video-based-ai-robots-visual.html","tags":["نموذج عالمي","تخطيط","Harvard","انتشار"],"timestamp":"2026-03-26T10:20:03Z"},{"id":"0401-012","title":"حلّ ازدحام روبوتات المستودع يرفع إنتاجية Amazon 25% في المحاكاة","summary":"تعلّم مُتحكّم التعلّم المُعزَّز متعدد الوكلاء (MARL) المدرَّب في محاكاة عالية الدقة لمستودع Amazon الوقاية المسبقة من ازدحام الروبوتات بالتنبؤ باختناقات المرور قبل 30 ثانية. تخطّط Amazon لبدء تجارب تشغيلية في الواقع خلال الربع الثالث من 2026.","image":"https://images.unsplash.com/photo-1531746790731-6c087fecd65a?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-ai-warehouse-robot-traffic-boosting.html","tags":["مستودع","Amazon","MARL","كفاءة"],"timestamp":"2026-03-26T09:30:01Z"},{"id":"0401-013","title":"Lucid Bots تجمع 20 مليون دولار: الطلب على طائرات غسيل النوافذ والضغط العالي ينفجر","summary":"يتسارع أصحاب المباني التجارية في تبنّي طائرات Lucid Bots بدون طيار للتنظيف مع تصاعد تكاليف العمالة وصرامة لوائح السلامة في الأعمال اليدوية على الارتفاع. ستموّل جولة السلسلة B البالغة 20 مليون دولار توسيع التصنيع وتطوير طائرة جديدة لإصلاح الواجهات.","image":"https://images.unsplash.com/photo-1527430253228-e93688616381?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/25/lucid-bots-raises-20m-to-keep-up-with-demand-for-its-window-washing-drones/","tags":["طائرات بدون طيار","تنظيف","تجاري","تمويل"],"timestamp":"2026-03-25T11:00:00Z"},{"id":"0401-014","title":"روبوتات هوائية ترفع 100 ضعف وزنها: اختراق Arizona State University الهوائي","summary":"تستخدم العضلات الهوائية الفائقة الجديدة من Arizona State University الهواء المضغوط والهندسة الحيوية الإلهام لتحقيق نسب قوة إلى وزن تفوق عضلة الإنسان بمئة ضعف. تتحمّل المُشغِّلات الماء المغلي والحمض والمواد الكاشطة، مما يجعلها مرشّحة للبيئات الصناعية والفضائية القاسية.","image":"https://images.unsplash.com/photo-1518770660439-4636190af475?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-04-air-powered-artificial-muscles-robots.html","tags":["مُشغِّل","هوائي","Arizona State","قوة"],"timestamp":"2026-04-02T11:20:06Z"},{"id":"0401-015","title":"روبوت حصاد الطماطم يتعلّم إعطاء الأولوية للقطف السهل ويرفع الغلّة 35%","summary":"تُحوّل خوارزمية حصاد مُدرِكة للصعوبة أداء روبوتات الزراعة من خلال التنبّؤ بأيّ الثمار ستكون أسهل في القطف قبل الاقتراب منها. تتجاوز التقنية الطماطم وقد جرى اختبارها بنجاح على الفراولة والفلفل.","image":"https://images.unsplash.com/photo-1531746790731-6c087fecd65a?w=400&h=250&fit=crop","source":"ScienceDaily","url":"https://www.sciencedaily.com/releases/2026/03/260317064512.htm","tags":["روبوتيات زراعية","حصاد","تخطيط","غذاء"],"timestamp":"2026-03-18T00:26:44Z"},{"id":"0401-016","title":"صفقة Gecko Robotics مع البحرية: روبوتات تسلّق الجدران ستفحص كل سفينة حربية أمريكية","summary":"ستفحص روبوتات تسلّق الجدران ذات الالتصاق المغناطيسي من Gecko Robotics هيكل وسلامة البنية الإنشائية لكل فئة من سفن البحرية الأمريكية بموجب عقد جديد لخمس سنوات. تجمع الروبوتات قراءات سماكة بالموجات فوق الصوتية أسرع 10 أضعاف من الغوّاصين البشريين، مُتيحةً صيانة استباقية بدلاً من تفاعلية.","image":"https://images.unsplash.com/photo-1542744173-8e7e53415bb0?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/17/gecko-robotics-lands-the-largest-u-s-navy-robotics-deal-yet/","tags":["بحرية","عسكري","فحص","روبوت متسلّق"],"timestamp":"2026-03-17T10:00:00Z"},{"id":"0401-017","title":"معيار Fraunhofer للروبوتات الإنسانية بخمسة مستويات: مستويات SAE لاستقلالية الروبوتات","summary":"نشر معهد Fraunhofer HNFIZ الألماني أوّل تصنيف قياسي لقدرات الروبوتات الإنسانية من خمسة مستويات يشمل الحركة والتعامل والاستقلالية المعرفية. المستوى الخامس — الاستقلالية المعرفية الكاملة — لا توجد حتى الآن أي روبوتات تجارية تبلغه، مما يُوفّر للصناعة هدفاً واضحاً على خارطة الطريق.","image":"https://images.unsplash.com/photo-1620712943543-bcc4688e7485?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-humanoid-robots-mobility-cognition.html","tags":["روبوت إنساني","معايير","استقلالية","Fraunhofer"],"timestamp":"2026-03-23T17:20:07Z"},{"id":"0401-018","title":"نموذج مشية بالشبكة العصبية يُحاكي حركة الحصان والكلب والقطة لتحسين الروبوتات رباعية الأرجل","summary":"تُستخدم شبكة عصبية بيولوجية الإلهام تُنمذج بدقة حركة الحيوانات رباعية الأرجل في مشيات المشي والهرولة والعدو لتحسين جودة حركة الروبوتات ذات الأرجل. يتعامل النموذج أيضاً مع انتقالات المشية التلقائية، وهو تحدٍّ طويل الأمد في التحكم بالروبوتات ذات الأرجل.","image":"https://images.unsplash.com/photo-1485827404703-89b55fcc595e?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-artificial-neural-network-gait-patterns.html","tags":["رباعي الأرجل","حركة","بيولوجي الإلهام","مشية"],"timestamp":"2026-03-23T17:20:08Z"},{"id":"0401-019","title":"روبوت تتبّع الروائح المستوحى من الحشرات يعمل حتى مع تلف أجهزة الاستشعار","summary":"يستطيع روبوت تتبّع الروائح المُتحمِّل للأعطال المستوحى من حاسة شمّ الحشرات تحديد تسرّبات الغاز والمتفجرات بشكل موثوق حتى عند تعطّل أحد صفيفَي أجهزة الاستشعار لديه. تُظهر الاختبارات الميدانية في البيئات الصناعية دقة ثابتة في الأوضاع الحقيقية.","image":"https://images.unsplash.com/photo-1545987796-200677ee1011?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-insect-robot-tracks-odors-antenna.html","tags":["شمّ","كشف الغاز","تحمّل الأعطال","بيولوجي الإلهام"],"timestamp":"2026-03-23T12:00:03Z"},{"id":"0401-020","title":"دروس الطائرات العسكرية الأوكرانية تُعيد تشكيل معايير سلامة السيارات ذاتية القيادة","summary":"يُبيّن تحليل IEEE Spectrum كيف تُوظَّف تقنيات الملاحة بـAI العدائي الرائدة في حرب الطائرات بدون طيار الأوكرانية — مقاومة الانتحال وملاحة مرنة ضد التشويش وتقييم التهديدات المستقل — في أنظمة القيادة المدنية الذاتية لمواجهة تعطيل GPS وهجمات أجهزة الاستشعار.","image":"https://images.unsplash.com/photo-1527430253228-e93688616381?w=400&h=250&fit=crop","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/military-drones-self-driving-cars","tags":["عسكري","قيادة ذاتية","أمان","ملاحة"],"timestamp":"2026-03-02T12:00:02Z"},{"id":"0401-021","title":"طائرة بدون طيار رفرافة على شكل طائر أكثر كفاءة ثلاثة أضعاف من الرباعي عند السرعة المنخفضة","summary":"يحقّق روبوت الأجنحة الرافرفة من Rutgers University ثلاثة أضعاف كفاءة الطاقة مقارنةً بالطائرة رباعية المحرّكات عند سرعات دون 5 م/ث، مما يجعله مثالياً لمهام رصد الحياة البرية طويلة الأمد. مُستوحى تصميم الجناح من تشريح صقر الشاهين وجرى تحسينه عبر 10,000 ساعة من محاكاة CFD.","image":"https://images.unsplash.com/photo-1529612700005-e35377bf1415?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-birdlike-robots-greater-flexibility-drones.html","tags":["أورنيثوبتر","بيولوجي الإلهام","كفاءة","حياة برية"],"timestamp":"2026-03-23T13:20:02Z"}]};

window.__NEWS_DATA_LOCALES__["ar-SA"]["2026-03-31"] = {"date":"2026-03-31","featured":{"id":"featured-0331","title":"روبوتات DNA قد تُوصِّل الأدوية وتصطاد الفيروسات داخل جسمك — دراسة في مجلة Nature","summary":"تُثبت دراسة بارزة نُشرت في مجلة Nature نجاح روبوتات نانوية مبنية على DNA في التنقل عبر مجرى الدم وتحديد الخلايا السرطانية من خلال بصمتها البروتينية السطحية، ثم الارتساء عليها وإطلاق حمولة علاج كيميائي بدقة دون الخلوية. حقّقت هذه التقنية انحساراً كاملاً للأورام في 80% من نماذج الفئران دون أي سمّية خارج الهدف.","image":"https://images.unsplash.com/photo-1576086213369-97a306d36557?w=1200&h=600&fit=crop","source":"ScienceDaily","url":"https://www.sciencedaily.com/releases/2026/03/260331001104.htm","tags":["روبوتات نانوية","السرطان","توصيل الأدوية","DNA"],"timestamp":"2026-03-31T07:16:58Z"},"articles":[{"id":"0331-001","title":"FedEx تُبرم شراكة مع Berkshire Gray في صفقة أتمتة روبوتية بقيمة 1.2 مليار دولار","summary":"اختارت FedEx استراتيجية قائمة على الشراكة، إذ تعاقدت مع Berkshire Gray لتركيب روبوتات فرز وتعامل مع الطرود مدعومة بالAI عبر 650 منشأة في الولايات المتحدة. جاء هذا القرار بعد ثلاث سنوات من التقييم الداخلي لبناء قدرة روبوتية مستقلة.","image":"https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/31/fedex-chooses-partnerships-over-proprietary-tech-for-its-automation-strategy/","tags":["FedEx","اللوجستيات","Berkshire Gray","الأتمتة"],"timestamp":"2026-03-31T15:46:50Z"},{"id":"0331-002","title":"Nomadic تُغلق جولة تمويل بـ 8.4 مليون دولار لبناء طبقة بنية تحتية لبيانات AI المادي","summary":"تحوّل Nomadic تدفقات الكاميرات الخام للروبوتات والمركبات ذاتية القيادة إلى مجموعات بيانات نظيفة ومنظمة وقابلة للبحث باستخدام التعلم العميق. بتمويل بلغ 8.4 مليون دولار في جولة السلسلة A، تعمل الشركة على توسيع طاقتها التشغيلية وإضافة دعم لأنواع مستشعرات LiDAR والرادار.","image":"https://images.unsplash.com/photo-1677442136019-21780ecad995?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/31/nomadic-raises-8-4-million-to-wrangle-the-data-pouring-off-avs/","tags":["شركة ناشئة","البيانات","AI المادي","التمويل"],"timestamp":"2026-03-31T15:00:00Z"},{"id":"0331-003","title":"ملاحة مرنة للروبوتات في الأماكن الضيقة: تقليل الحسابات بنسبة 80% بإطار عمل جديد","summary":"يُقلّل إطار عمل جديد لتخطيط المسارات للروبوتات اللينة والمستمرة الحسابات اللازمة بنسبة 80% مع الحفاظ على دقة الملاحة في الممرات الضيقة. يُتيح هذا الاختراق التحكم في الروبوتات اللينة في الوقت الفعلي على معالجات دقيقة اعتيادية دون الحاجة إلى تسريع GPU.","image":"https://images.unsplash.com/photo-1555255707-c07966088b7b?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-framework-flexible-robots-tight-spaces.html","tags":["الروبوتات اللينة","التحكم","الحوسبة","طبي"],"timestamp":"2026-03-31T17:40:06Z"},{"id":"0331-004","title":"Physical Intelligence تستهدف تقييماً بـ 11.2 مليار دولار بجمع تمويل جديد بمليار دولار","summary":"تُجري Physical Intelligence (π) مفاوضات متقدمة مع صناديق رأس المال الجريء من الفئة الأولى لجولة تمويل ترفع قيمتها إلى 11.2 مليار دولار في أقل من عام على انطلاقها. نموذج π0 الخاص بالشركة — أكثر دماغ روبوتي متعدد الأغراض كفاءة متاح — بات مرخّصاً من قِبل ستة مصنّعي أجهزة OEM.","image":"https://images.unsplash.com/photo-1620712943543-bcc4688e7485?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/27/physical-intelligence-is-reportedly-in-talks-to-raise-1-billion-again/","tags":["Physical Intelligence","π0","التمويل","النموذج التأسيسي"],"timestamp":"2026-03-27T23:59:40Z"},{"id":"0331-005","title":"فيديو الجمعة: Roadrunner — الروبوت ثنائي الأرجل الجامع بين العجلات والمشي","summary":"يُسلّط فيديو الجمعة في IEEE Spectrum الضوء على Roadrunner، وهو روبوت ثنائي الأرجل يضمّ عجلات قابلة للسحب في قدميه لحركة سريعة على الأرض المستوية، إلى جانب المشية الثنائية التقليدية للسلالم والتضاريس الوعرة. يُمثّل هذا التصميم الهجين اتجاهاً جديداً رئيسياً في حركة الروبوتات الشبيهة بالبشر.","image":"https://images.unsplash.com/photo-1535378917042-10a22c95931a?w=400&h=250&fit=crop","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/roadrunner-bipedal-robot","video":"https://www.youtube.com/watch?v=tF4DML7FIWk","tags":["ثنائي الأرجل","عجلات","هجين","الحركة"],"timestamp":"2026-03-27T16:30:03Z"},{"id":"0331-006","title":"ميكروروبوتات فيزيائية بحتة تتنقل كالحيوانات — بلا إلكترونيات","summary":"تتنقل الميكروروبوتات المطبوعة ثلاثية الأبعاد من جامعة Leiden عبر التدرجات الكيميائية والتيارات بالاعتماد فقط على الفيزياء السلبية لهندستها المطبوعة. دون أي إلكترونيات أو منطق تحكم، تكلّف كل روبوت أقل من سنت واحد، ويمكن تصنيع ملايين منها لأسراب المراقبة البيئية.","image":"https://images.unsplash.com/photo-1563207153-f403bf289096?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-alive-tiny-3d-robots-animals.html","tags":["ميكروروبوتات","Leiden","سلبي","سرب"],"timestamp":"2026-03-27T09:40:04Z"},{"id":"0331-007","title":"طائرة BRINC Guardian المسيّرة تُشعل جدلاً حول الحريات المدنية: Narcan + Starlink + مطاردة بـ 96 كم/ساعة","summary":"تدمج طائرة الشرطة المسيّرة Guardian من BRINC تقنية Starlink وإمكانية نشر Narcan والمطاردة بسرعة 96 كم/ساعة، مما يجعلها الطائرة المسيّرة للسلامة العامة الأكثر قدرة التي عُرضت تجارياً. طالبت منظمات الخصوصية والحريات المدنية بعقد جلسات استماع في الكونغرس حول طائرات الشرطة المسيّرة ذاتية القيادة.","image":"https://images.unsplash.com/photo-1527430253228-e93688616381?w=400&h=250&fit=crop","source":"Ars Technica","url":"https://arstechnica.com/gadgets/2026/03/brincs-new-police-drone-uses-starlink-carries-narcan-chases-vehicles-at-60mph/","tags":["طائرة شرطة مسيّرة","الحريات المدنية","BRINC","الأخلاقيات"],"timestamp":"2026-03-25T21:12:03Z"},{"id":"0331-008","title":"أسطول روبوتات الطاقة الشمسية الأسترالي يغطي 13,000 كيلومتر من الصحراء سنوياً تحت حرارة 50 درجة مئوية","summary":"أسطول من روبوتات الفحص المدعومة بالAI يتولى الآن صيانة أكبر مزارع الطاقة الشمسية في أستراليا عبر 13,000 كيلومتر من التضاريس الداخلية. يعمل في درجات حرارة كانت ستُودخل العمال البشر المستشفيات، إذ يرفع هذا الأسطول معدل اكتشاف الأعطال بنسبة 400% مع تخفيض تكاليف الصيانة بنسبة 70%.","image":"https://images.unsplash.com/photo-1545987796-200677ee1011?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-robots-humans-biggest-solar-farms.html","tags":["الطاقة الشمسية","أستراليا","صناعي","التفتيش"],"timestamp":"2026-03-25T18:10:07Z"},{"id":"0331-009","title":"رؤية ميلانيا ترامب للتعليم المنزلي عبر الروبوتات تُشعل نقاشاً في تكنولوجيا التعليم","summary":"أشعل تأييد السيدة الأولى ميلانيا ترامب لروبوتات Figure AI الشبيهة بالبشر كمعلمين منزليين بالAI نقاشاً محتدماً بين المعلمين وأولياء الأمور وعلماء النفس المتخصصين في الأطفال. يستشهد المؤيدون بإمكانية التعليم المُخصَّص تماماً، فيما يُحذّر المنتقدون من مخاطر على التنمية الاجتماعية.","image":"https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/25/melania-trump-wants-a-robot-to-homeschool-your-child/","tags":["التعليم","Figure AI","السياسة","شبيه بالإنسان"],"timestamp":"2026-03-25T18:55:41Z"},{"id":"0331-010","title":"طائرات Lucid Bots المسيّرة لغسيل النوافذ: 20 مليون دولار لتوسيع الإنتاج مع تجاوز الطلب للعرض","summary":"تبني Lucid Bots منشأة تصنيع ثانية لتلبية الطلب المتصاعد على طائراتها المسيّرة ذاتية القيادة لغسيل النوافذ والتنظيف بالضغط العالي. مع تزايد عزوف أصحاب المباني عن إرسال عمال على السقالات، انتقل التنظيف الخارجي الروبوتي من كونه رفاهية إلى ضرورة.","image":"https://images.unsplash.com/photo-1527430253228-e93688616381?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/25/lucid-bots-raises-20m-to-keep-up-with-demand-for-its-window-washing-drones/","tags":["طائرات مسيّرة","التنظيف","العقارات التجارية","التوسع"],"timestamp":"2026-03-25T11:00:00Z"},{"id":"0331-011","title":"سوار EMG يتحكم في اليد الاصطناعية بدقة تصل إلى مستوى الإصبع الواحد","summary":"يقرأ سوار EMG الذي طوّره MIT في وقت واحد 34 إشارة عضلية من الساعد لتوفير تحكم فردي في الوقت الفعلي لأصابع اليد الاصطناعية. يُحقق هذا النظام غير الجراحي نتائج كانت ممكنة سابقاً فقط مع الأقطاب الكهربائية المزروعة، مع أقل من 20 ساعة من تدريب المستخدم.","image":"https://images.unsplash.com/photo-1561557944-6e7860d1a7eb?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-wristband-enables-wearers-robotic-movements.html","tags":["الأطراف الاصطناعية","EMG","أجهزة قابلة للارتداء","إمكانية الوصول"],"timestamp":"2026-03-25T06:00:09Z"},{"id":"0331-012","title":"يد روبوتية بلا محرك تستخدم سبيكة ذاكرة الشكل للتشغيل في أقل من 100 مللي ثانية بوزن 180 غراماً","summary":"باستبدال المحركات المؤازِرة بمحركات أسلاك سبيكة ذاكرة الشكل، بنى الباحثون يداً روبوتية خماسية الأصابع تزن 180 غراماً فقط، وتستطيع فتح وإغلاق كل إصبع على حدة في أقل من 100 مللي ثانية، وهو ما يكفي لمهام التلاعب الدقيق.","image":"https://images.unsplash.com/photo-1561557944-6e7860d1a7eb?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-robotic-motors-shifting-actuator.html","tags":["اليد الروبوتية","SMA","خفيف الوزن","محرك"],"timestamp":"2026-03-25T10:00:04Z"},{"id":"0331-013","title":"Agile Robots + Google DeepMind: أحدث شراكة AI-عتاد في مجال الروبوتات","summary":"مع اشتداد السباق للهيمنة على سوق AI المادي، انضمت Agile Robots إلى القائمة المتنامية من شركات العتاد التي تتشارك مع Google DeepMind. يأتي هذا الاتفاق في أعقاب اتفاقيات مماثلة بين DeepMind وكل من Boston Dynamics وFigure AI وApptronik.","image":"https://images.unsplash.com/photo-1555255707-c07966088b7b?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/24/agile-robots-becomes-the-latest-robotics-company-to-partner-with-google-deepmind/","tags":["Agile Robots","DeepMind","AI","الشراكة"],"timestamp":"2026-03-24T12:05:00Z"},{"id":"0331-014","title":"دروس حرب الطائرات المسيّرة في أوكرانيا: كيف يُعيد AI القتال ذاتي التشغيل تشكيل سلامة السيارات ذاتية القيادة","summary":"تُكيَّف تقنيات الملاحة دون GPS والدفاع ضد خداع المستشعرات ومتانة AI التعاندية، التي طُوّرت لطائرات قتالية أوكرانية مسيّرة، لتناسب المركبات ذاتية القيادة المدنية. يُمثّل هذا النقل التكنولوجي العابر للمجالات حالة فريدة من الابتكار العسكري السابق للتطبيقات الاستهلاكية.","image":"https://images.unsplash.com/photo-1542744173-8e7e53415bb0?w=400&h=250&fit=crop","source":"IEEE Spectrum","url":"https://spectrum.ieee.org/autonomous-drone-warfare","tags":["عسكري","القيادة الذاتية","الأمن","نقل التكنولوجيا"],"timestamp":"2026-03-24T13:00:05Z"},{"id":"0331-015","title":"انهيار مطعم Haidilao AgiBot: درس تحذيري في نشر الروبوتات","summary":"أصبح الفيديو الذي انتشر على الإنترنت لنادل شبيه بالإنسان من AgiBot يرقص بصورة عشوائية في مطعم بسيليكون فالي دراسةً في النشر الروبوتي المفرط الثقة. يكشف الحادث كيف تُعرّي الحالات الاستثنائية في البيئات الحقيقية الثغرات في أنظمة الروبوتات المدرّبة في المحاكاة.","image":"https://images.unsplash.com/photo-1620712943543-bcc4688e7485?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/19/restaurant-dancing-robot-went-wild-hot-pot-cupertino-haidilao-agibot/","tags":["AgiBot","النشر","الفشل","مطعم"],"timestamp":"2026-03-19T21:13:50Z"},{"id":"0331-016","title":"نقل المهارات عبر الأجساد المختلفة يُتيح للأذرع الروبوتية التعلم من تجارب الروبوتات الشبيهة بالبشر","summary":"يُتيح إطار تعلم قائم على النوايا لذراع روبوتية على سطح طاولة اكتساب مهارات من تجارب روبوت شبيه بالإنسان بالكامل، رغم اختلاف البُنية الجسدية جذرياً. الفكرة المحورية أن نوايا المهمة يمكن تجريدها عن الشكل المادي وإعادة توجيهها نحو أجساد جديدة.","image":"https://images.unsplash.com/photo-1535378917042-10a22c95931a?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-03-robots-bodies-skills-intention-based.html","tags":["التعلم النقلي","Cross-Embodiment","المهارة","AI"],"timestamp":"2026-03-30T13:20:04Z"},{"id":"0331-017","title":"سرب Georgia Tech عديم الدماغ: ذكاء جماعي ميكانيكي بحت مُثبَت","summary":"يُمثّل سرب الروبوتات الميكانيكي البحت من Georgia Tech — الأول الذي يُحقق سلوكاً جماعياً موجّهاً نحو هدف دون أي إلكترونيات — تحولاً جذرياً في روبوتات الأسراب. تستخدم الروبوتات تفاعلات تثبيت الشكل الفيزيائي للتنقل جماعياً نحو مصادر الضوء.","image":"https://images.unsplash.com/photo-1518770660439-4636190af475?w=400&h=250&fit=crop","source":"TechXplore","url":"https://techxplore.com/news/2026-04-robotic-swarm-electronics-batteries-brains.html","tags":["سرب","الذكاء الجماعي","Georgia Tech","ميكانيكي"],"timestamp":"2026-04-01T10:00:02Z"},{"id":"0331-018","title":"جولة السلسلة A لـ Mind Robotics بـ 500 مليون دولار: مشروع روبوتات المصانع الجديد للرئيس التنفيذي لشركة Rivian","summary":"جمع RJ Scaringe نصف مليار دولار لـ Mind Robotics، راهناً على أن روبوتات المصانع المصممة خصيصاً لمهامها — بدلاً من الشكل البشري — ستهيمن على الأتمتة الصناعية. المنصة الأولى للشركة مُصممة خصيصاً لعمليات تجميع مركبات EV.","image":"https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/11/rivian-mind-robotics-series-a-500m-fund-raise-industrial-ai-powered-robots/","tags":["Mind Robotics","التمويل","EV","صناعي"],"timestamp":"2026-03-11T16:12:02Z"},{"id":"0331-019","title":"روبوت التوصيل المتسلق للسلالم Rivr من Amazon: من المدخل إلى الباب","summary":"يجمع روبوت التوصيل ذو العجلات من Rivr قاعدة بعجلات مع ملحقات قابلة للسحب لتسلق الدرج، مما يُمكّنه من التنقل في المباني السكنية متعددة الطوابق دون مصاعد. يُشير استحواذ Amazon على Rivr إلى نيّة الشركة في تقديم توصيل منزلي ذاتي القيادة لأي عنوان مستقبلاً.","image":"https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/19/amazon-acquires-rivr-maker-of-a-stair-climbing-delivery-robot/","tags":["Amazon","التوصيل","الميل الأخير","الدرج"],"timestamp":"2026-03-19T23:28:37Z"},{"id":"0331-020","title":"حصّادة طماطم بالAI تتنبأ بصعوبة القطف وتزيد الغلة بنسبة 35%","summary":"تستخدم روبوت زراعي جديد رؤية الحاسوب والتعلم الآلي للتنبؤ بصعوبة حصاد كل طماطمة قبل الاقتراب منها، مُعطياً الأولوية للقطف السهل لتعظيم معدل الحصاد الإجمالي. أظهرت اختبارات البيوت المحمية غلةً أعلى بنسبة 35% واستهلاكاً للطاقة أقل بنسبة 28% لكل كيلوغرام محصود.","image":"https://images.unsplash.com/photo-1531746790731-6c087fecd65a?w=400&h=250&fit=crop","source":"ScienceDaily","url":"https://www.sciencedaily.com/releases/2026/03/260317064512.htm","tags":["الروبوتات الزراعية","الحصاد","AI","الكفاءة"],"timestamp":"2026-03-18T00:26:44Z"},{"id":"0331-021","title":"Qualcomm IQ10 مقابل Nvidia: بدأت حرب الرقائق على أدمغة الروبوتات الشبيهة بالبشر","summary":"تُمثّل شراكة Qualcomm مع Neura Robotics لاستخدام معالج AI IQ10 كمنصة حوسبة لروبوت شبيه بالإنسان أول تحدٍّ تجاري جدي لهيمنة Nvidia في الحوسبة الروبوتية. يُقدّم IQ10 أداءً بـ 40 TOPS بأقل من 20 واط، وهو عرض مُغرٍ للروبوتات الشبيهة بالإنسان التي تعمل بالبطاريات.","image":"https://images.unsplash.com/photo-1535378917042-10a22c95931a?w=400&h=250&fit=crop","source":"TechCrunch","url":"https://techcrunch.com/2026/03/09/qualcomms-partnership-with-neura-robotics-is-just-the-beginning/","tags":["Qualcomm","Neura Robotics","الرقائق","التنافس"],"timestamp":"2026-03-09T15:58:11Z"}]};
